(function() {
var ms_ch_1_Verses = [
  {num:1,words:[["O Afioga a le Atua,", "The words of God,"], ["na fetalai e ia ia Mose i le taimi na aveina a'e ai Mose i se mauga maualuga tele lava,", "which he spake unto Moses at a time when Moses was caught up into an exceedingly high mountain ,"]]},
  {num:2,words:[["Ma sa vaai faafesagai lava o ia i le Atua,", "And he saw God face to face ,"], ["ma sa talanoa o ia ma ia,", "and he talked with him,"], ["ma sa i luga o Mose le mamalu o le Atua;", "and the glory of God was upon Moses;"], ["o lea na mafai ai e Mose ona gafatia lona mamalu.", "therefore Moses could endure his presence."]]},
  {num:3,words:[["Ma sa fetalai mai le Atua ia Mose,", "And God spake unto Moses,"], ["ua fai mai:", "saying:"], ["Faauta,", "Behold,"], ["o A'u o le Alii le Atua Malosi Aoao,", "I am the Lord God Almighty ,"], ["ma o Lē Gata o lo'u igoa;", "and Endless is my name ;"], ["ona ua aunoa Au ma se amataga o aso po o se gataaga o tausaga;", "for I am without beginning of days or end of years;"], ["ma e lē o le lē gata ea lea?", "and is not this endless?"]]},
  {num:4,words:[["Ma,", "And,"], ["faauta,", "behold,"], ["o oe lava o lo'u atalii;", "thou art my son;"], ["o le mea lea ia vaai ,", "wherefore look ,"], ["ma o le a Ou faaali atu ia te oe galuega a o'u lima ;", "and I will show thee the workmanship of mine hands ;"], ["ae lē o galuega uma,", "but not all,"], ["aua o a'u galuega ua aunoa ma se gataaga ,", "for my works are without end ,"], ["ma a'u upu foi,", "and also my words ,"], ["aua e lē uma lava i latou.", "for they never cease."]]},
  {num:5,words:[["O le mea lea,", "Wherefore,"], ["e leai se tagata e mafai ona vaai i a'u galuega uma,", "no man can behold all my works ,"], ["vagana ua vaai o ia i lo'u mamalu atoa;", "except he behold all my glory ;"], ["ma e leai se tagata e mafai ona vaai i lo'u mamalu atoa,", "and no man can behold all my glory ,"], ["ma tumau pea i la le tino i le lalolagi pe a uma ona vaai i ai.", "and afterwards remain in the flesh on the earth."]]},
  {num:6,words:[["Ma ua ia te a'u se galuega mo oe,", "And I have a work for thee,"], ["Mose e,", "Moses,"], ["lo'u atalii;", "my son;"], ["ma ua tusa oe ma la'u Toatasi na Fanaua;", "and thou art in the similitude of mine Only Begotten ;"], ["ma o la'u Toatasi na Fanaua o le Faaola ma o le a avea ma Faaola ,", "and mine Only Begotten is and shall be the Savior ,"], ["ona ua tumu o ia i le alofa tunoa ma le upumoni ;", "for he is full of grace and truth ;"], ["peitai ua leai se isi Atua e ese mai ia te a'u,", "but there is no God beside me,"], ["ma ua i ai mea uma i o'u luma,", "and all things are present with me,"], ["ona ua Ou iloa i latou uma.", "for I know them all."]]},
  {num:7,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["o le mea lenei e tasi Ou te faaali atu ia te oe,", "this one thing I show unto thee,"], ["Mose e,", "Moses,"], ["lo'u atalii;", "my son,"], ["aua o loo e i le lalolagi;", "for thou art in the world,"], ["ma o le a Ou faaalia atu nei ia te oe.", "and now I show it unto thee."]]},
  {num:8,words:[["Ma sa oo ina vaai atu Mose,", "And it came to pass that Moses looked,"], ["ma vaai atu i le lalolagi na foafoa ai o ia i ona luga;", "and beheld the world upon which he was created;"], ["ma sa vaaia e Mose le lalolagi ma ona tuluiga,", "and Moses beheld the world and the ends thereof,"], ["ma le fanauga uma a tagata o i ai,", "and all the children of men which are,"], ["ma e na foafoaina;", "and which were created;"], ["o lea lava mea sa ofo ma maofa tele ai o ia.", "of the same he greatly marveled and wondered."]]},
  {num:9,words:[["Ma sa oo ina afio ese le Atua mai ia Mose,", "And the presence of God withdrew from Moses,"], ["sa oo ina lē i ai lona mamalu i luga o Mose;", "that his glory was not upon Moses;"], ["ma sa tuua Mose ia te ia lava. Ma ina ua tuua o ia ia te ia lava,", "and Moses was left unto himself. And as he was left unto himself,"], ["sa pa'ū o ia i le eleele.", "he fell unto the earth."]]},
  {num:10,words:[["Ma sa oo ina faato'ā toe maua e Mose i le va o itula e tele lona malosi masani ai e pei o le tagata;", "And it came to pass that it was for the space of many hours before Moses did again receive his natural strength like unto man;"], ["ma sa fai ifo o ia ia te ia lava:", "and he said unto himself:"], ["O lenei,", "Now,"], ["ona o lenei mea ua ou iloa ai o le tagata o se mea noa,", "for this cause I know that man is nothing ,"], ["o se mea ou te le'i mafaufauina lava.", "which thing I never had supposed."]]},
  {num:11,words:[["A'o lenei ua vaai o'u lava mata i le Atua ;", "But now mine own eyes have beheld God;"], ["ae e lē o o'u mata faaletino ,", "but not my natural ,"], ["a'o o'u mata faaleagaga,", "but my spiritual eyes,"], ["aua sa lē mafai e o'u mata faaletino ona vaaia;", "for my natural eyes could not have beheld ;"], ["po ua ou mamae ma oti i ona luma;", "for I should have withered and died in his presence;"], ["ae sa i ai lona mamalu i o'u luga;", "but his glory was upon me;"], ["ma sa ou vaai i ona fofoga ,", "and I beheld his face ,"], ["ona sa liua a'u i ona luma.", "for I was transfigured before him."]]},
  {num:12,words:[["Ma sa oo ina ua uma ona fai atu e Mose nei upu,", "And it came to pass that when Moses had said these words,"], ["faauta,", "behold,"], ["sa alu ane Satani ma faaosooso ia te ia,", "Satan came tempting him,"], ["ua fai mai:", "saying:"], ["Mose e,", "Moses,"], ["le atalii o le tagata,", "son of man,"], ["ifo mai ia te a'u.", "worship me."]]},
  {num:13,words:[["Ma sa oo ina vaai atu Mose ia Satani ma fai atu:", "And it came to pass that Moses looked upon Satan and said:"], ["O ai oe? Aua faauta,", "Who art thou? For behold,"], ["o a'u o se atalii o le Atua,", "I am a son of God,"], ["i le faatusa o lana Toatasi na Fanaua;", "in the similitude of his Only Begotten;"], ["ma o fea o i ai lou mamalu,", "and where is thy glory ,"], ["e tatau ai ona ou ifo atu ia te oe?", "that I should worship thee?"]]},
  {num:14,words:[["Aua faauta,", "For behold,"], ["sa lē mafai ona ou vaai atu i le Atua,", "I could not look upon God,"], ["vagana ua oo mai lona mamalu i o'u luga,", "except his glory should come upon me,"], ["ma liua a'u i ona luma.", "and I were transfigured before him."], ["Ae ua mafai ona ou vaai atu ia te oe i le tulaga tagata faaletino.", "But I can look upon thee in the natural man."], ["Pe ua lē moni ea lea?", "Is it not so, surely?"]]},
  {num:15,words:[["Ia faamanūina lava le suafa o lo'u Atua,", "Blessed be the name of my God,"], ["ona ua lē alu ese atoa lona Agaga mai ia te a'u,", "for his Spirit hath not altogether withdrawn from me,"], ["a lē o lea o fea o i ai lou mamalu,", "or else where is thy glory,"], ["aua ua pouliuli ia te a'u? Ma e mafai ona ou iloa le eseesega o oe ma le Atua;", "for it is darkness unto me? And I can judge between thee and God;"], ["ona na fetalai mai le Atua ia te a'u:", "for God said unto me:"], ["Ifo atu i le Atua,", "Worship God,"], ["aua nao ia lava e te auauna atu i ai.", "for him only shalt thou serve ."]]},
  {num:16,words:[["Alu ese ia oe,", "Get thee hence,"], ["Satani;", "Satan;"], ["aua e te taufaasese mai ia te a'u;", "deceive me not;"], ["aua na fetalai mai le Atua ia te a'u:", "for God said unto me:"], ["Ua tusa oe ma la'u Toatasi na Fanaua.", "Thou art after the similitude of mine Only Begotten."]]},
  {num:17,words:[["Ma sa ia tuu mai foi ia te a'u poloaiga ina ua fetalai mai o ia ia te a'u i le laau na mu,", "And he also gave me commandments when he called unto me out of the burning bush ,"], ["ua fai mai:", "saying:"], ["Valaau atu i le Atua i le suafa o la'u Toatasi na Fanaua,", "Call upon God in the name of mine Only Begotten,"], ["ma ifo mai ia te a'u.", "and worship me."]]},
  {num:18,words:[["Ma sa toe fai atu Mose:", "And again Moses said:"], ["O le a ou lē tuua le valaau atu i le Atua,", "I will not cease to call upon God,"], ["ua i ai ia te a'u isi mea e ole atu ai ia te ia:", "I have other things to inquire of him:"], ["aua sa i ai lona mamalu i o'u luga,", "for his glory has been upon me,"], ["o le mea lea ua mafai ai ona ou iloa le eseesega o ia ma oe. Alu ese ia ma iinei,", "wherefore I can judge between him and thee. Depart hence,"], ["Satani.", "Satan."]]},
  {num:19,words:[["Ma o lenei,", "And now,"], ["ina ua uma ona fai atu e Mose nei upu,", "when Moses had said these words,"], ["sa alaga Satani ma le leo tele,", "Satan cried with a loud voice,"], ["ma sa leoleoā i luga o le eleele,", "and ranted upon the earth,"], ["ma faatonu mai,", "and commanded,"], ["ua fai mai:", "saying:"], ["O a'u o le Toatasi na Fanaua,", "I am the Only Begotten ,"], ["ifo mai ia te a'u.", "worship me."]]},
  {num:20,words:[["Ma sa oo ina amata ona fefe tele Mose;", "And it came to pass that Moses began to fear exceedingly;"], ["ma ina ua amata ona fefe o ia,", "and as he began to fear,"], ["sa vaai o ia i le oona o seoli . E ui i lea,", "he saw the bitterness of hell . Nevertheless,"], ["sa maua e ia le malosi,", "calling upon God,"], ["i le valaau atu i le Atua,", "he received strength ,"], ["ma sa ia faatonu atu,", "and he commanded,"], ["ua fai atu:", "saying:"], ["Satani,", "Depart from me,"], ["alu ese ia mai ia te a'u,", "Satan,"], ["aua ua nao le Atua lenei e tasi o le a ou ifo atu i ai,", "for this one God only will I worship,"], ["o le Atua lea o le mamalu.", "which is the God of glory ."]]},
  {num:21,words:[["Ma o lenei sa amata ona gatete Satani ,", "And now Satan began to tremble,"], ["ma sa luluina le eleele;", "and the earth shook;"], ["ma sa maua e Mose le malosi,", "and Moses received strength,"], ["ma valaau atu i le Atua,", "and called upon God,"], ["ua fai atu:", "saying:"], ["I le suafa o le Toatasi na Fanaua,", "In the name of the Only Begotten,"], ["alu ese ia ma iinei,", "depart hence,"], ["Satani.", "Satan ."]]},
  {num:22,words:[["Ma sa oo ina alaga Satani ma le leo tele,", "And it came to pass that Satan cried with a loud voice,"], ["i le tagi,", "with weeping,"], ["ma le tagiauē,", "and wailing,"], ["ma le lilivau o nifo;", "and gnashing of teeth;"], ["ma sa alu ese o ia mai i ina,", "and he departed hence,"], ["mai luma lava o Mose,", "even from the presence of Moses,"], ["sa oo ina lē vaaia o ia e ia.", "that he beheld him not."]]},
  {num:23,words:[["Ma o lenei sa molimau mai Mose lenei mea;", "And now of this thing Moses bore record;"], ["ae ona o le amioleaga ua lē i ai ai i totonu o le fanauga a tagata.", "but because of wickedness it is not had among the children of men."]]},
  {num:24,words:[["Ma sa oo ina ua alu ese Satani mai luma o Mose,", "And it came to pass that when Satan had departed from the presence of Moses,"], ["sa tepa a'e mata o Mose i le lagi,", "that Moses lifted up his eyes unto heaven,"], ["ua tumu i le Agaga Paia,", "being filled with the Holy Ghost ,"], ["lea e molimau e uiga i le Tamā ma le Alo;", "which beareth record of the Father and the Son;"]]},
  {num:25,words:[["Ma a'o valaau atu i le suafa o le Atua,", "And calling upon the name of God,"], ["sa toe vaaia e ia lona mamalu,", "he beheld his glory again,"], ["aua sa i luga o ia;", "for it was upon him;"], ["ma sa ia faalogoina se siufofoga,", "and he heard a voice ,"], ["ua fetalai mai:", "saying:"], ["Amuia lava oe Mose,", "Blessed art thou, Moses,"], ["ona o A'u,", "for I,"], ["o le Malosi Aoao,", "the Almighty,"], ["na filifilia oe,", "have chosen thee,"], ["ma o le a faia oe ia e malosi e sili atu nai lo vai e tele,", "and thou shalt be made stronger than many waters ;"], ["ona o le a latou usiusitai i lau poloai e pei o oe o le Atua .", "for they shall obey thy command as if thou wert God ."]]},
  {num:26,words:[["Ma faauta,", "And lo,"], ["Ou te faatasi ma oe,", "I am with thee ,"], ["e oo lava i le iuga o ou aso;", "even unto the end of thy days;"], ["aua o le a e laveai lo'u nuu mai le pologa ,", "for thou shalt deliver my people from bondage ,"], ["o Isaraelu lava lea la'u filifilia .", "even Israel my chosen ."]]},
  {num:27,words:[["Ma sa oo ina a'o fetalai mai pea le siufofoga,", "And it came to pass,"], ["sa tepa atu mata o Mose ma vaai atu i le lalolagi,", "as the voice was still speaking,"], ["ioe,", "Moses cast his eyes and beheld the earth, yea,"], ["le lalolagi atoa lava;", "even all of it;"], ["ma sa leai sona fasimea sa lei vaaia e ia,", "and there was not a particle of it which he did not behold,"], ["ma iloa i ai e ala i le Agaga o le Atua.", "discerning it by the Spirit of God."]]},
  {num:28,words:[["Ma sa vaai foi o ia i e o nonofo ai,", "And he beheld also the inhabitants thereof,"], ["ma sa leai se agaga sa lei vaaia e ia;", "and there was not a soul which he beheld not;"], ["ma sa iloa e ia i latou e ala i le Agaga o le Atua;", "and he discerned them by the Spirit of God;"], ["ma o o latou aofai sa matua toatele lava,", "and their numbers were great,"], ["sa lē mafaitaulia lava e pei o le oneone o le matafaga.", "even numberless as the sand upon the sea shore."]]},
  {num:29,words:[["Ma sa vaaia e ia laueleele e tele;", "And he beheld many lands;"], ["ma sa ta'ua ia laueleele taitasi o lalolagi ,", "and each land was called earth ,"], ["ma sa i ai ni isi sa nonofo ai.", "and there were inhabitants on the face thereof."]]},
  {num:30,words:[["Ma sa oo ina talosaga atu Mose i le Atua,", "And it came to pass that Moses called upon God,"], ["ua fai atu:", "saying:"], ["Ou te ole atu ia te oe,", "Tell me,"], ["sei ta'u mai ia te a'u,", "I pray thee,"], ["pe aisea ua faapea ona i ai o ia mea,", "why these things are so,"], ["ma o a mea na e faia ai i latou?", "and by what thou madest them?"]]},
  {num:31,words:[["Ma faauta,", "And behold,"], ["sa i luga o Mose le mamalu o le Alii,", "the glory of the Lord was upon Moses,"], ["o lea na tu ai Mose i luma o le Atua,", "so that Moses stood in the presence of God,"], ["ma talanoa faafesagai ma ia. Ma sa fetalai mai le Alii le Atua ia Mose:", "and talked with him face to face . And the Lord God said unto Moses:"], ["E mo la'u lava fuafuaga na Ou faia ai nei mea. O le poto lenei ma e tumau pea ia te a'u.", "For mine own purpose have I made these things. Here is wisdom and it remaineth in me."]]},
  {num:32,words:[["Ma o le upu a lo'u mana,", "And by the word of my power,"], ["na Ou foafoa ai i latou,", "have I created them,"], ["o ia lea o lo'u Atalii e Toatasi na Fanaua,", "which is mine Only Begotten Son,"], ["o lē ua tumu i le alofa tunoa ma le 'upumoni .", "who is full of grace and truth."]]},
  {num:33,words:[["Ma e lē mafaitaulia lalolagi ua Ou foafoaina ;", "And worlds without number have I created ;"], ["ma sa Ou foafoaina foi i latou mo lo'u lava faamoemoe;", "and I also created them for mine own purpose;"], ["ma o lo'u Atalii, o lē o la'u Toatasi na Fanaua,", "and by the Son I created them,"], ["na Ou foafoaina ai i latou.", "which is mine Only Begotten ."]]},
  {num:34,words:[["Ma o le uluai tagata o tagata uma ua Ou faaigoaina o Atamu ,", "And the first man of all men have I called Adam ,"], ["e toatele .", "which is many ."]]},
  {num:35,words:[["Ae ua nao se tala o le lalolagi lenei,", "But only an account of this earth,"], ["ma e o nonofo ai,", "and the inhabitants thereof,"], ["Ou te tuu atu ia te oe. Aua faauta,", "give I unto you. For behold,"], ["e i ai lalolagi e tele ua mavae atu e ala i le upu a lo'u mana. Ma e i ai le tele o loo tutu nei,", "there are many worlds that have passed away by the word of my power. And there are many that now stand,"], ["ma ua lē mafaitaulia i latou i le tagata;", "and innumerable are they unto man;"], ["ae ua faitaulia mea uma ia te a'u,", "but all things are numbered unto me,"], ["aua e a a'u i latou ma ua Ou iloa i latou.", "for they are mine and I know them."]]},
  {num:36,words:[["Ma sa oo ina fai atu Mose i le Alii,", "And it came to pass that Moses spake unto the Lord,"], ["ua faapea atu:", "saying:"], ["Ia e alofa mutimutivale mai i lau auauna,", "Be merciful unto thy servant,"], ["E,", "O God,"], ["le Atua e, ma ta'u mai ia te a'u e uiga i le lalolagi lenei,", "and tell me concerning this earth,"], ["ma e o nonofo ai,", "and the inhabitants thereof,"], ["ma le lagi foi,", "and also the heavens,"], ["ona malie ai lea o lau auauna.", "and then thy servant will be content."]]},
  {num:37,words:[["Ma sa fetalai mai le Alii le Atua ia Mose,", "And the Lord God spake unto Moses,"], ["ua fai mai:", "saying:"], ["O lagi ,", "The heavens ,"], ["e tele,", "they are many,"], ["ma e lē mafai ona faitaulia i latou i le tagata;", "and they cannot be numbered unto man;"], ["ae ua faitaulia i latou ia te a'u,", "but they are numbered unto me,"], ["ona e a a'u i latou.", "for they are mine."]]},
  {num:38,words:[["Ma e pei ona o le a mavae atu le tasi lalolagi,", "And as one earth shall pass away,"], ["ma ona lagi o le a faapea foi ona tu mai se isi;", "and the heavens thereof even so shall another come;"], ["ma e leai se gataaga i a'u galuega,", "and there is no end to my works,"], ["pe i a'u upu.", "neither to my words."]]},
  {num:39,words:[["Aua faauta,", "For behold,"], ["o la'u galuega ma lo'u mamalu lenei—ia aumaia le tino ola pea ma le ola faavavau o le tagata.", "this is my work and my glory —to bring to pass the immortality and eternal life of man."]]},
  {num:40,words:[["Ma o lenei,", "And now,"], ["Mose e,", "Moses,"], ["lo'u atalii,", "my son,"], ["o le a Ou tautala atu ia te oe e uiga i le lalolagi lenei o loo e tu ai;", "I will speak unto thee concerning this earth upon which thou standest;"], ["ma ia e tusia mea o le a Ou tautala atu ai.", "and thou shalt write the things which I shall speak."]]},
  {num:41,words:[["Ma i se aso e manatu ai le fanauga a tagata i a'u upu o ni meanoa ma aveese le tele o o i latou mai le tusi o le a e tusia,", "And in a day when the children of men shall esteem my words as naught and take many of them from the book which thou shalt write,"], ["faauta,", "behold,"], ["o le a Ou faatu mai se tasi e pei o oe;", "I will raise up another like unto thee;"], ["ma o le a toe i ai ia mea i totonu o le fanauga a tagata—i totonu o le toatele o e e talitonu.", "and they shall be had again among the children of men—among as many as shall believe."]]},
  {num:42,words:[["(O upu nei na tulei mai ia Mose i le mauga,", "(These words were spoken unto Moses in the mount,"], ["o lona igoa o le a lē iloa i totonu o le fanauga a tagata. Ma o lenei ua fetalai atu ia te oe. Aua le faaalia atu i soo se tasi vagana ai i latou o e e talitonu. E faapea lava. Amene.)", "the name of which shall not be known among the children of men. And now they are spoken unto you. Show them not unto any except them that believe. Even so. Amen.)"]]},
];
renderVerseSet(ms_ch_1_Verses, 'ms-ch1-verses');

var ms_ch_2_Verses = [
  {num:1,words:[["Ma sa oo ina fetalai mai le Alii ia Mose,", "And it came to pass that the Lord spake unto Moses,"], ["ua fai mai:", "saying:"], ["Faauta,", "Behold,"], ["Ou te faaali atu ia te oe e uiga i le lagi lenei,", "I reveal unto you concerning this heaven ,"], ["ma le lalolagi lenei;", "and this earth ;"], ["ia tusi upu o le a Ou tautala atu ai. O A'u o le Amataga ma le Gataaga,", "write the words which I speak. I am the Beginning and the End,"], ["le Atua Malosi Aoao;", "the Almighty God ;"], ["o la'u Toatasi na Fanaua na Ou foafoa ai ia mea uma;", "by mine Only Begotten I created these things;"], ["ioe,", "yea,"], ["na Ou foafoaina i le amataga le lagi,", "in the beginning I created the heaven ,"], ["ma le lalolagi ua e tu ai.", "and the earth upon which thou standest."]]},
  {num:2,words:[["Ma sa aunoa le lalolagi ma se faatulagaga,", "And the earth was without form ,"], ["ma sa gaogao;", "and void;"], ["ma sa Ou faia le pouliuli ia oo mai i luga o le moana;", "and I caused darkness to come up upon the face of the deep;"], ["ma sa fegaoioiai lo'u Agaga i luga o le fogatai;", "and my Spirit moved upon the face of the water;"], ["aua o A'u o le Atua.", "for I am God."]]},
  {num:3,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na Ou fai atu:", "said:"], ["Ia i ai le malamalama ;", "Let there be light ;"], ["ma sa i ai le malamalama.", "and there was light."]]},
  {num:4,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["sa vaai atu i le malamalama;", "saw the light;"], ["ma ua lelei lena malamalama. Ma o A'u,", "and that light was good . And I,"], ["o le Atua,", "God,"], ["na vavaeeseina le malamalama mai le pouliuli.", "divided the light from the darkness."]]},
  {num:5,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na ta'ua le malamalama o le Ao;", "called the light Day;"], ["ma o le pouliuli,", "and the darkness,"], ["sa Ou ta'ua o le Po;", "I called Night;"], ["ma o lenei mea sa Ou faia i le upu a lo'u mana,", "and this I did by the word of my power,"], ["ma sa faia lava e pei ona sa Ou fai atu ai;", "and it was done as I spake ;"], ["ma o le afiafi ma le taeao o le aso muamua lea.", "and the evening and the morning were the first day ."]]},
  {num:6,words:[["Ma sa toe fai atu A'u,", "And again,"], ["o le Atua:", "I,"], ["Ia i ai se vanimonimo i le lotoi o le vai,", "God, said:"], ["ma sa faapea ona i ai,", "Let there be a firmament in the midst of the water,"], ["e pei lava ona Ou fai atu;", "and it was so,"], ["ma sa Ou fai atu:", "even as I spake; and I said:"], ["Ia tuu atu e vavae ai vai mai vai;", "Let it divide the waters from the waters;"], ["ma sa faia lava;", "and it was done;"]]},
  {num:7,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na faia le vanimonimo ma vaevaeina vai ,", "made the firmament and divided the waters ,"], ["ioe,", "yea,"], ["vai tetele i lalo o le vanimonimo mai vai sa i luga o le vanimonimo,", "the great waters under the firmament from the waters which were above the firmament,"], ["ma sa faapea lava e pei ona sa Ou fai atu ai.", "and it was so even as I spake."]]},
  {num:8,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na ta'ua le vanimonimo o le Lagi ;", "called the firmament Heaven ;"], ["ma o le afiafi ma le taeao o le aso lua lea.", "and the evening and the morning were the second day."]]},
  {num:9,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na Ou fai atu:", "said:"], ["Ia tuu atu i vai o i lalo ifo o le lagi ia faapotopoto faatasi i se mea e tasi,", "Let the waters under the heaven be gathered together unto one place,"], ["ma sa faapea lava;", "and it was so;"], ["ma o A'u,", "and I,"], ["o le Atua,", "God,"], ["na Ou fai atu:", "said:"], ["Ia i ai se laueleele matutu;", "Let there be dry land;"], ["ma sa faapea lava.", "and it was so."]]},
  {num:10,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na Ou ta'ua le laueleele matutu o le Eleele ;", "called the dry land Earth ;"], ["ma o le faapotopotoga faatasi o vai,", "and the gathering together of the waters,"], ["na Ou ta'ua o le Sami;", "called I the Sea;"], ["ma o A'u,", "and I,"], ["o le Atua,", "God,"], ["sa Ou vaai atu ua lelei ia mea uma ua Ou faia.", "saw that all things which I had made were good."]]},
  {num:11,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["sa Ou fai atu:", "said:"], ["Ia tuu atu i le eleele ia faatutupu mai mutia ,", "Let the earth bring forth grass ,"], ["le laau afu ia fua mai i fatu,", "the herb yielding seed,"], ["ma le laau 'aina ia fua mai i fua,", "the fruit tree yielding fruit,"], ["e tusa ma lona ituaiga,", "after his kind,"], ["ma le laau fua ia fua mai i fua,", "and the tree yielding fruit,"], ["o ona fatu e tatau ona i ai ia te ia lava i luga o le eleele,", "whose seed should be in itself upon the earth,"], ["ma sa faapea lava e pei ona sa Ou fai atu.", "and it was so even as I spake."]]},
  {num:12,words:[["Ma sa aumai e le eleele le mutia,", "And the earth brought forth grass,"], ["laau afu uma e fua i fatu e tusa ma lona ituaiga,", "every herb yielding seed after his kind,"], ["ma le laau e fua mai i fua,", "and the tree yielding fruit,"], ["o ona fatu ua i totonu o ia lava,", "whose seed should be in itself,"], ["e tusa ma lona ituaiga;", "after his kind ;"], ["ma o A'u,", "and I,"], ["o le Atua,", "God,"], ["sa Ou vaai atu ua lelei mea uma ua Ou faia;", "saw that all things which I had made were good;"]]},
  {num:13,words:[["Ma o le afiafi ma le taeao o le aso tolu lea.", "And the evening and the morning were the third day."]]},
  {num:14,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na Ou fai atu:", "said:"], ["Ia i ai ni malamalama i le vanimonimo o le lagi,", "Let there be lights in the firmament of the heaven,"], ["e vavae ai le ao mai le po,", "to divide the day from the night,"], ["ma ia tuu i latou e avea ma faailoga,", "and let them be for signs,"], ["ma mo tau,", "and for seasons,"], ["ma mo aso,", "and for days,"], ["ma mo tausaga;", "and for years;"]]},
  {num:15,words:[["Ma ia tuu i latou e avea ma malamalama i le vanimonimo o le lagi e tuu atu ai le malamalama i luga o le lalolagi;", "And let them be for lights in the firmament of the heaven to give light upon the earth;"], ["ma sa faapea lava.", "and it was so."]]},
  {num:16,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na faia ni malamalama tetele e lua;", "made two great lights;"], ["o le malamalama tele e pulea le ao,", "the greater light to rule the day,"], ["ma le malamalama itiiti e pulea le po,", "and the lesser light to rule the night,"], ["ma o le malamalama tele o le la,", "and the greater light was the sun,"], ["ma o le malamalama itiiti o le masina;", "and the lesser light was the moon;"], ["ma sa faia foi fetu e tusa lava ma la'u upu.", "and the stars also were made even according to my word."]]},
  {num:17,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na tuua i laua i le vanimonimo o le lagi e tuu mai ai le malamalama i luga o le lalolagi,", "set them in the firmament of the heaven to give light upon the earth,"]]},
  {num:18,words:[["Ma o le la e pule i le ao,", "And the sun to rule over the day,"], ["ma le masina e pule i le po,", "and the moon to rule over the night,"], ["ma vavae ai le malamalama mai le pouliuli;", "and to divide the light from the darkness ;"], ["ma o A'u,", "and I,"], ["o le Atua,", "God,"], ["na vaai atu ua lelei mea uma ua Ou faia;", "saw that all things which I had made were good;"]]},
  {num:19,words:[["Ma o le afiafi ma le taeao o le aso fa lea.", "And the evening and the morning were the fourth day."]]},
  {num:20,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na fai atu:", "said:"], ["Ia tuu atu i vai ia aumai ia matua tele meaola fegaoioiai ua i ai le ola,", "Let the waters bring forth abundantly the moving creature that hath life,"], ["ma manufelelei e mafai ona felelei i luga a'e o le lalolagi i le vanimonimo ateatea o le lagi.", "and fowl which may fly above the earth in the open firmament of heaven."]]},
  {num:21,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na foafoaina tafola tetele,", "created great whales ,"], ["ma meaola uma e gaoioi,", "and every living creature that moveth,"], ["sa tele ona aumai e vai,", "which the waters brought forth abundantly,"], ["e tusa ma o latou ituaiga,", "after their kind,"], ["ma manufelelei faiapaau taitasi e tusa ma lona ituaiga;", "and every winged fowl after his kind;"], ["ma o A'u,", "and I,"], ["o le Atua,", "God,"], ["sa Ou vaai atu ua lelei mea uma ua Ou foafoaina.", "saw that all things which I had created were good."]]},
  {num:22,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["sa faamanuiaina i latou,", "blessed them,"], ["ua fai atu:", "saying:"], ["Ia uluola,", "Be fruitful,"], ["ma faateleina ,", "and multiply ,"], ["ma faatumu ai vai i le sami;", "and fill the waters in the sea;"], ["ma ia tuu atu i manufelelei ia faateleina i le lalolagi;", "and let fowl multiply in the earth;"]]},
  {num:23,words:[["Ma o le afiafi ma le taeao o le aso lima lea.", "And the evening and the morning were the fifth day."]]},
  {num:24,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na fai atu:", "said:"], ["Ia tuu atu i le eleele e aumai meaola e tusa ma lona ituaiga,", "Let the earth bring forth the living creature after his kind,"], ["o manu faatoaga,", "cattle,"], ["ma mea fetolofi,", "and creeping things,"], ["ma manu vaefa o le lalolagi e tusa ma o latou ituaiga;", "and beasts of the earth after their kind,"], ["ma sa faapea lava;", "and it was so;"]]},
  {num:25,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na faia manu vaefa o le lalolagi e tusa ma o latou ituaiga,", "made the beasts of the earth after their kind,"], ["ma manu faatoaga e tusa ma o latou ituaiga;", "and cattle after their kind,"], ["ma mea fetolofi taitasi uma i luga o le lalolagi e tusa ma lona ituaiga;", "and everything which creepeth upon the earth after his kind;"], ["ma o A'u,", "and I,"], ["o le Atua,", "God,"], ["na vaai atu ua lelei ia mea uma.", "saw that all these things were good."]]},
  {num:26,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na fai atu i la'u Toatasi na Fanaua,", "said unto mine Only Begotten ,"], ["lea sa faatasi ma A'u mai le amataga:", "which was with me from the beginning :"], ["Inā ta faia ia o le tagata i lo ta'ua faatusa ,", "Let us make man in our image ,"], ["e tusa ma o ta'ua foliga;", "after our likeness;"], ["ma sa faapea lava. Ma o A'u,", "and it was so. And I,"], ["o le Atua,", "God,"], ["na fai atu:", "said:"], ["Ia tuu atu ia te i laua e pule i i'a o le sami,", "Let them have dominion over the fishes of the sea,"], ["ma i manufelelei o le ea,", "and over the fowl of the air,"], ["ma i manu faatoaga,", "and over the cattle,"], ["ma i le lalolagi atoa,", "and over all the earth,"], ["ma i mea fetolofi uma e fetolofi i luga o le lalolagi.", "and over every creeping thing that creepeth upon the earth."]]},
  {num:27,words:[["Ma o A'u,", "And I,"], ["o le Atua ,", "God,"], ["na foafoaina le tagata i lo'u lava faatusa,", "created man in mine own image ,"], ["o le faatusa o la'u Toatasi na Fanaua na Ou foafoaina ai o ia;", "in the image of mine Only Begotten created I him;"], ["o le tane ma le fafine na Ou foafoaina ai i laua.", "male and female created I them."]]},
  {num:28,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na faamanuiaina i laua,", "blessed them,"], ["ma fai atu ia te i laua:", "and said unto them:"], ["Ia fanafanau,", "Be fruitful ,"], ["ma uluuluola ,", "and multiply ,"], ["ma faatumuina le lalolagi,", "and replenish the earth,"], ["ma faato'a i ai,", "and subdue it,"], ["ma ia pule i i'a o le sami,", "and have dominion over the fish of the sea,"], ["ma i manufelelei o le ea,", "and over the fowl of the air,"], ["ma i meaola uma e fegaoioia'i i luga o le lalolagi.", "and over every living thing that moveth upon the earth."]]},
  {num:29,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["sa fai atu i le tagata:", "said unto man:"], ["Faauta,", "Behold,"], ["ua Ou tuu atu ia te oe laau afu uma e fua i fatu,", "I have given you every herb bearing seed,"], ["ia ua i luga o le lalolagi atoa,", "which is upon the face of all the earth,"], ["ma laau uma e i ai fua o laau e fua i fatu;", "and every tree in the which shall be the fruit of a tree yielding seed;"], ["ia avea ia ma meaai ia te oe.", "to you it shall be for meat ."]]},
  {num:30,words:[["Ma o manuvaefa uma o le lalolagi,", "And to every beast of the earth,"], ["ma manufelelei uma o le ea,", "and to every fowl of the air,"], ["ma mea uma e fetolofi i luga o le lalolagi,", "and to everything that creepeth upon the earth,"], ["ua Ou tuuina i ai le ola,", "wherein I grant life,"], ["o le a tuu atu i ai laau afu mama uma mo meaai;", "there shall be given every clean herb for meat;"], ["ma sa faapea lava,", "and it was so,"], ["e pei ona sa Ou fai atu ai.", "even as I spake."]]},
  {num:31,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["na vaai atu i mea uma na Ou faia,", "saw everything that I had made,"], ["ma,", "and,"], ["faauta,", "behold,"], ["o mea uma na Ou faia sa lelei tele lava;", "all things which I had made were very good ;"], ["ma o le afiafi ma le taeao o le aso ono lea.", "and the evening and the morning were the sixth day."]]},
];
renderVerseSet(ms_ch_2_Verses, 'ms-ch2-verses');

var ms_ch_3_Verses = [
  {num:1,words:[["Sa faapea ona mae'a o le lagi ma le lalolagi,", "Thus the heaven and the earth were finished,"], ["ma 'au uma o i latou.", "and all the host of them."]]},
  {num:2,words:[["Ma o le aso fitu na faagata ai e A'u,", "And on the seventh day I,"], ["o le Atua,", "God,"], ["la'u galuega,", "ended my work,"], ["ma mea uma na Ou faia;", "and all things which I had made;"], ["ma sa Ou malolo i le aso lona fitu mai la'u galuega atoa,", "and I rested on the seventh day from all my work,"], ["ma o mea uma sa Ou faia ua mae'a,", "and all things which I had made were finished,"], ["ma o A'u,", "and I,"], ["o le Atua,", "God,"], ["sa Ou vaai atu ua lelei i latou;", "saw that they were good;"]]},
  {num:3,words:[["Ma o A'u,", "And I,"], ["o le Atua,", "God,"], ["sa Ou faamanuiaina le aso fitu,", "blessed the seventh day, and sanctified it;"], ["ma faapaiaina;", "because that in it I had rested from all my work which I,"], ["aua o le aso lea na Ou malolo ai mai la'u galuega atoa lea na foafoa ma faia e A'u,", "God,"], ["o le Atua.", "had created and made."]]},
  {num:4,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["Ou te fai atu ia te oe,", "I say unto you,"], ["o vaevaega ia o le lagi ma le lalolagi,", "that these are the generations of the heaven and of the earth,"], ["ina ua foafoaina i latou, i le aso na faia ai,", "when they were created ,"], ["e A'u,", "in the day that I,"], ["o le Alii le Atua,", "the Lord God,"], ["le lagi ma le lalolagi,", "made the heaven and the earth,"]]},
  {num:5,words:[["Ma laau taitasi o le fanua ae lei i ai i le lalolagi,", "And every plant of the field before it was in the earth,"], ["ma laau afu taitasi o le fanua ae lei tupu mai.", "and every herb of the field before it grew."], ["Aua o A'u,", "For I,"], ["o le Alii le Atua,", "the Lord God,"], ["na foafoaina faaleagaga mea uma,", "created all things, of which I have spoken,"], ["ia ua Ou fai atu ai,", "spiritually ,"], ["ae lei i ai faaletino i latou i luga o le lalolagi.", "before they were naturally upon the face of the earth."], ["Aua e lei faia e A'u,", "For I,"], ["o le Alii le Atua,", "the Lord God,"], ["ia timu i luga o le lalolagi.", "had not caused it to rain upon the face of the earth."], ["Ma o A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God,"], ["na foafoaina le fanauga uma a tagata;", "had created all the children of men;"], ["ma sa lei i ai se tagata e galueaiina le eleele ;", "and not yet a man to till the ground ;"], ["aua sa Ou foafoaina i latou i le lagi ;", "for in heaven created I them;"], ["ma sa lei i ai se mea tino aano i luga o le lalolagi,", "and there was not yet flesh upon the earth,"], ["po o i le vai,", "neither in the water,"], ["po o i le ea;", "neither in the air;"]]},
  {num:6,words:[["Peitai o A'u,", "But I,"], ["o le Alii le Atua,", "the Lord God,"], ["sa Ou fai atu,", "spake,"], ["ona alu a'e ai lea se puao mai le lalolagi,", "and there went up a mist from the earth,"], ["ma faasūsū ai le eleele atoa.", "and watered the whole face of the ground."]]},
  {num:7,words:[["Ma o A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God,"], ["na faia le tagata mai le efuefu o le eleele,", "formed man from the dust of the ground,"], ["ma mānava i ona pogaiisu le mānava o le ola;", "and breathed into his nostrils the breath of life ;"], ["ma sa avea ai le tagata o se tagata ola,", "and man became a living soul ,"], ["o le mea tino aano muamua lea i luga o le lalolagi,", "the first flesh upon the earth,"], ["o le tagata muamua foi;", "the first man also;"], ["e ui i lea,", "nevertheless,"], ["o mea uma sa foafoaina muamua;", "all things were before created;"], ["ae sa foafoaina faaleagaga i latou ma faia e tusa ma la'u upu.", "but spiritually were they created and made according to my word."]]},
  {num:8,words:[["Ma o A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God,"], ["na totoina se faatoaga i sasa'e i Etena ,", "planted a garden eastward in Eden ,"], ["ma o iina na Ou tuuina ai le tagata na Ou faia.", "and there I put the man whom I had formed."]]},
  {num:9,words:[["Ma o A'u,", "And out of the ground made I,"], ["o le Alii le Atua,", "the Lord God,"], ["na faia ia tutupu mai,", "to grow every tree,"], ["faaletino,", "naturally ,"], ["i fafo o le eleele,", "that is pleasant to the sight of man;"], ["laau uma e matagofie i le vaai a le tagata;", "and man could behold it. And it became also a living soul. For it was spiritual in the day that I created it;"], ["ma sa mafai ona vaai i ai le tagata. Ma sa avea o se tagata ola. Ona sa faaleagaga i le aso na Ou foafoa ai;", "for it remaineth in the sphere in which I,"], ["aua ua tumau i le sifia na foafoa ai e A'u,", "God,"], ["o le Atua,", "created it,"], ["ioe,", "yea,"], ["mea uma lava na Ou saunia mo le faaaogaina e le tagata;", "even all things which I prepared for the use of man;"], ["ma sa vaai le tagata ua lelei mo meaai. Ma o A'u,", "and man saw that it was good for food. And I,"], ["o le Alii le Atua,", "the Lord God,"], ["sa totoina foi le laau o le ola i le totonugalemu o le faatoaga,", "planted the tree of life also in the midst of the garden,"], ["ma le laau foi e iloa ai le lelei ma le leaga.", "and also the tree of knowledge of good and evil."]]},
  {num:10,words:[["Ma o A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God,"], ["na faia se vaitafe ia tafe atu i fafo mai Etena e faasūsū ai le faatoaga;", "caused a river to go out of Eden to water the garden;"], ["ma sa vaevae atu mai iina,", "and from thence it was parted,"], ["ma avea ma ni vaitafe autu e fa.", "and became into four heads ."]]},
  {num:11,words:[["Ma o A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God,"], ["na faaigoaina le igoa o le muamua o Pisona,", "called the name of the first Pison,"], ["ma sa tafe taamilo atu i le laueleele atoa o Havila, i lea mea,", "and it compasseth the whole land of Havilah ,"], ["na foafoa ai e A'u,", "where I,"], ["o le Alii le Atua,", "the Lord God,"], ["auro e tele;", "created much gold;"]]},
  {num:12,words:[["Ma sa lelei le auro o lena laueleele,", "And the gold of that land was good,"], ["ma sa i ai le petala ma maa soama.", "and there was bdellium and the onyx stone."]]},
  {num:13,words:[["Ma o le igoa o le vaitafe lona lua sa ta'ua o Kaiona;", "And the name of the second river was called Gihon;"], ["o lea lava ua taamilo i le laueleele atoa o Aitiope.", "the same that compasseth the whole land of Ethiopia ."]]},
  {num:14,words:[["Ma o le igoa o le vaitafe lona tolu o Hitekelu;", "And the name of the third river was Hiddekel;"], ["o lena lea na alu atu agai i sasa'e o Asuria. Ma o le vaitafe lona fa o le Eufirate.", "that which goeth toward the east of Assyria. And the fourth river was the Euphrates."]]},
  {num:15,words:[["Ma sa ave e A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God,"], ["le tagata,", "took the man,"], ["ma tuu o ia i le Faatoaga o Etena,", "and put him into the Garden of Eden ,"], ["e galueaiina,", "to dress it,"], ["ma ia tausia.", "and to keep it."]]},
  {num:16,words:[["Ma o A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God,"], ["na poloaiina le tagata,", "commanded the man,"], ["ua fai atu:", "saying:"], ["O laau uma o le faatoaga e mafai ona e 'ai saoloto ai,", "Of every tree of the garden thou mayest freely eat,"]]},
  {num:17,words:[["Ae o le laau e iloa ai le lelei ma le leaga,", "But of the tree of the knowledge of good and evil,"], ["aua e te 'ai ai;", "thou shalt not eat of it,"], ["e ui i lea,", "nevertheless,"], ["e mafai ona e filifili mo oe lava,", "thou mayest choose for thyself,"], ["ona ua tuuina atu ia te oe;", "for it is given unto thee;"], ["peitai,", "but,"], ["ia manatua ua Ou faasaina,", "remember that I forbid it,"], ["aua o le aso e te 'aia ai e te oti moni ai lava.", "for in the day thou eatest thereof thou shalt surely die ."]]},
  {num:18,words:[["Ma o A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God,"], ["na fai atu i la'u Toatasi na Fanaua,", "said unto mine Only Begotten ,"], ["e lē lelei ona nofo toatasi o le tagata;", "that it was not good that the man should be alone ;"], ["o le mea lea,", "wherefore,"], ["o le a Ou faia ai se fesoasoani e tatau ai mo ia.", "I will make an help meet for him."]]},
  {num:19,words:[["Ma na faia e A'u,", "And out of the ground I,"], ["o le Alii le Atua,", "the Lord God,"], ["i fafo mai le eleele,", "formed every beast of the field,"], ["manu vaefa uma o le fanua,", "and every fowl of the air;"], ["ma manufelelei uma o le ea;", "and commanded that they should come unto Adam,"], ["ma poloaiina ia latou o mai ia Atamu,", "to see what he would call them;"], ["e vaai po o a igoa o le a ia faaigoa ai i latou; sa o ni mea ola foi i latou;", "and they were also living souls;"], ["aua sa mānava atu e A'u,", "for I,"], ["o le Atua,", "God,"], ["ia te i latou le mānava o le ola,", "breathed into them the breath of life ,"], ["ma poloaiina o soo se mea e faaigoa ai e Atamu mea ola taitasi,", "and commanded that whatsoever Adam called every living creature,"], ["o lona igoa lava lena.", "that should be the name thereof."]]},
  {num:20,words:[["Ma sa tuu atu e Atamu igoa i manu faatoaga uma,", "And Adam gave names to all cattle,"], ["ma manufelelei o le ea,", "and to the fowl of the air,"], ["ma manu vaefa uma o le fanua;", "and to every beast of the field;"], ["ae o Atamu,", "but as for Adam,"], ["sa lei maua se fesoasoani e tatau ai mo ia.", "there was not found an help meet for him."]]},
  {num:21,words:[["Ma o A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God,"], ["na faia ia oo mai se moe gase i luga o Atamu;", "caused a deep sleep to fall upon Adam;"], ["ma sa moe o ia,", "and he slept,"], ["ma sa Ou to mai se tasi o ona ivi 'aso'aso ma faasoo le aano i lona tulaga;", "and I took one of his ribs and closed up the flesh in the stead thereof;"]]},
  {num:22,words:[["Ma o le ivi 'aso'aso na to mai e A'u,", "And the rib which I,"], ["o le Alii le Atua,", "the Lord God,"], ["mai le tane,", "had taken from man,"], ["na Ou faia ai se fafine ,", "made I a woman ,"], ["ma aumai o ia i le tane.", "and brought her unto the man."]]},
  {num:23,words:[["Ma sa fai mai Atamu:", "And Adam said:"], ["Ua ou iloa nei o le ivi lenei o o'u ivi,", "This I know now is bone of my bones,"], ["ma le aano o o'u aano;", "and flesh of my flesh;"], ["o le a ta'ua o ia o le Fafine,", "she shall be called Woman,"], ["aua sa to mai fafo o ia mai le tane.", "because she was taken out of man."]]},
  {num:24,words:[["O lea e tu'ua ai e se tane lona tamā ma lona tinā,", "Therefore shall a man leave his father and his mother,"], ["ma ia pipii atu i lana ava;", "and shall cleave unto his wife ;"], ["ma o le a avea i laua ma tino e tasi.", "and they shall be one flesh."]]},
  {num:25,words:[["Ma sa lē lavalavā i laua uma,", "And they were both naked,"], ["o le tane ma lana ava,", "the man and his wife,"], ["sa lē maasiasi foi i laua.", "and were not ashamed."]]},
];
renderVerseSet(ms_ch_3_Verses, 'ms-ch3-verses');

var ms_ch_4_Verses = [
  {num:1,words:[["Ma o A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God ,"], ["na fai atu ia Mose,", "spake unto Moses,"], ["ua faapea atu:", "saying:"], ["O Satani lena,", "That Satan ,"], ["o lē na e faatonu i le suafa o la'u Toatasi na Fanaua,", "whom thou hast commanded in the name of mine Only Begotten,"], ["o ia lava lea sa i ai mai le amataga ,", "is the same which was from the beginning ,"], ["ma sa sau o ia i o'u luma,", "and he came before me,"], ["ma fai mai—Faauta, o a'u lenei,", "saying—Behold,"], ["auina atu a'u,", "here am I,"], ["o le a avea a'u mo ou atalii,", "send me,"], ["ma o le a ou laveaiina tagata uma,", "I will be thy son,"], ["ina ia leai se agaga e toatasi e se ese,", "and I will redeem all mankind,"], ["ma e moni lava o le a ou faia lena mea;", "that one soul shall not be lost,"], ["o le mea lea,", "and surely I will do it;"], ["ia tuu mai ia te a'u lou mamalu.", "wherefore give me thine honor."]]},
  {num:2,words:[["Ae,", "But,"], ["faauta,", "behold,"], ["o lo'u Atalii Pele,", "my Beloved Son ,"], ["o lē o la'u Pele ma la'u Filifilia mai le amataga,", "which was my Beloved and Chosen from the beginning,"], ["na fai mai ia te a'u—Le Tamā e,", "said unto me— Father ,"], ["ia faia lou finagalo ,", "thy will be done,"], ["ma e a oe pea le mamalu e faavavau.", "and the glory be thine forever."]]},
  {num:3,words:[["O le mea lea,", "Wherefore,"], ["ona sa fouvale Satani ia te a'u,", "because that Satan rebelled against me,"], ["ma saili e faaumatia le faitalia a le tagata,", "and sought to destroy the agency of man,"], ["lea na tuu atu e A'u,", "which I,"], ["o le Alii le Atua ia te ia,", "the Lord God, had given him,"], ["ma le tasi foi,", "and also,"], ["ia Ou avatu ia te ia lo'u lava mana;", "that I should give unto him mine own power;"], ["i le mana o la'u Toatasi na Fanaua,", "by the power of mine Only Begotten,"], ["na Ou faia ai ia lafoina o ia i lalo;", "I caused that he should be cast down ;"]]},
  {num:4,words:[["Ma sa avea o ia ma Satani,", "And he became Satan ,"], ["ioe,", "yea,"], ["o le tiapolo lava lea,", "even the devil ,"], ["o le tamā o pepelo uma,", "the father of all lies ,"], ["e faasese ma faatauaso tagata,", "to deceive and to blind men,"], ["ma taitai faatagataotaua i latou i lona loto,", "and to lead them captive at his will,"], ["le toatele lava lea o i latou o e e lē faalogo mai i lo'u leo.", "even as many as would not hearken unto my voice."]]},
  {num:5,words:[["Ma o lenei sa sili atu le atamai o le gata nai lo soo se isi o manu vaefa uma o le fanua ia na faia e A'u,", "And now the serpent was more subtle than any beast of the field which I, the Lord God,"], ["o le Alii le Atua.", "had made."]]},
  {num:6,words:[["Ma sa tuu e Satani i le loto o le gata,", "And Satan put it into the heart of the serpent,"], ["(ona e toatele na ia taitai ese ia mulimuli atu ia te ia,", "(for he had drawn away many after him,"], [") ma sa saili foi o ia e faasese Eva ,", ") and he sought also to beguile Eve,"], ["aua sa lē iloa e ia le mafaufau o le Atua,", "for he knew not the mind of God,"], ["o le mea lea na saili ai o ia e faaumatia le lalolagi.", "wherefore he sought to destroy the world."]]},
  {num:7,words:[["Ma sa fai atu o ia i le fafine:", "And he said unto the woman:"], ["Ioe,", "Yea,"], ["na fetalai mai ea le Atua—Aua lua te aai i laau uma o le faatoaga ? (Ma sa tautala mai o ia i le gutu o le gata.)", "hath God said—Ye shall not eat of every tree of the garden? (And he spake by the mouth of the serpent.)"]]},
  {num:8,words:[["Ma sa fai atu le fafine i le gata:", "And the woman said unto the serpent:"], ["E mafai ona ma aai i fua o laau uma o le faatoaga;", "We may eat of the fruit of the trees of the garden;"]]},
  {num:9,words:[["Ae o le fua o le laau lena ua e vaai atu i ai o i le totonugalemu o le faatoaga,", "But of the fruit of the tree which thou beholdest in the midst of the garden,"], ["na fetalai mai le Atua—Aua e te lua aai ai,", "God hath said—Ye shall not eat of it,"], ["pe e te lua pa'i atu i ai,", "neither shall ye touch it,"], ["ne'i oti ai oulua.", "lest ye die."]]},
  {num:10,words:[["Ma sa fai atu le gata i le fafine:", "And the serpent said unto the woman :"], ["Lua te lē oti lava;", "Ye shall not surely die;"]]},
  {num:11,words:[["Aua ua iloa e le Atua o le aso lua te aai ai,", "For God doth know that in the day ye eat thereof,"], ["ona pupula ai lea o oulua mata ,", "then your eyes shall be opened,"], ["ma o le a avea ai oulua e pei o atua,", "and ye shall be as gods,"], ["e iloa le lelei ma le leaga.", "knowing good and evil."]]},
  {num:12,words:[["Ma ina ua vaai atu le fafine ua lelei le laau mo meaai,", "And when the woman saw that the tree was good for food,"], ["ma ua matagofie i le vaai,", "and that it became pleasant to the eyes,"], ["ma o se laau ua manaomia e faapoto ai o ia,", "and a tree to be desired to make her wise,"], ["sa ave e ia lona fua,", "she took of the fruit thereof,"], ["ma 'ai ,", "and did eat ,"], ["ma sa avatu foi e ia i lana tane faatasi ma ia,", "and also gave unto her husband with her,"], ["ma sa ai ai foi o ia.", "and he did eat."]]},
  {num:13,words:[["Ma sa pupula mata o i laua uma,", "And the eyes of them both were opened,"], ["ma sa la iloa sa laua lē lavalavā. Ma sa la su'i faatasi lau o le mati ma fai ni ufiufi mo i laua lava.", "and they knew that they had been naked . And they sewed fig leaves together and made themselves aprons ."]]},
  {num:14,words:[["Ma sa la faalogoina le siufofoga o le Alii le Atua,", "And they heard the voice of the Lord God,"], ["a'o la savalivali i le faatoaga,", "as they were walking in the garden,"], ["i le mālū o le aso;", "in the cool of the day;"], ["ma sa o atu Atamu ma lana ava e faalalafi i laua lava mai luma o le Alii le Atua i totonu o laau o le faatoaga.", "and Adam and his wife went to hide themselves from the presence of the Lord God amongst the trees of the garden."]]},
  {num:15,words:[["Ma o A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God,"], ["na valaau atu ia Atamu,", "called unto Adam,"], ["ma fai atu ia te ia:", "and said unto him:"], ["O fea ua e alu i ai?", "Where goest thou?"]]},
  {num:16,words:[["Ma sa tali mai o ia:", "And he said:"], ["Sa ou faalogoina lou siufofoga i le faatoaga,", "I heard thy voice in the garden,"], ["ma sa ou fefe,", "and I was afraid,"], ["aua sa ou vaai ua ou le lavalavā,", "because I beheld that I was naked,"], ["ma sa ou lafi ai.", "and I hid myself."]]},
  {num:17,words:[["Ma o A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God,"], ["na fai atu ia Atamu:", "said unto Adam:"], ["O ai na fai atu ia te oe ua e lē lavalavā? Ua e 'ai i le laau na Ou poloaiina ai oe e aua e te 'ai ai,", "Who told thee thou wast naked? Hast thou eaten of the tree whereof I commanded thee that thou shouldst not eat,"], ["afai e te 'ai ai o le a e oti lava?", "if so thou shouldst surely die ?"]]},
  {num:18,words:[["Ma sa fai mai le tane:", "And the man said:"], ["O le fafine na e aumai ia te a'u,", "The woman thou gavest me,"], ["ma poloaiina ia mau faatasi ma a'u,", "and commandest that she should remain with me,"], ["na ia aumai ia te a'u le fua o le laau ma na ou 'ai ai.", "she gave me of the fruit of the tree and I did eat."]]},
  {num:19,words:[["Ma o A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God,"], ["na fai atu i le fafine:", "said unto the woman:"], ["O le a lenei mea ua e faia? Ma sa fai mai le fafine:", "What is this thing which thou hast done? And the woman said:"], ["Na faasese a'u e le gata,", "The serpent beguiled me,"], ["ma na ou 'ai ai.", "and I did eat."]]},
  {num:20,words:[["Ma o A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God,"], ["na fai atu i le gata:", "said unto the serpent:"], ["Ona ua e faia lenei mea o le a sili ona fetuuina oe i lo manu faatoaga uma,", "Because thou hast done this thou shalt be cursed above all cattle,"], ["ma manu vaefa uma o le fanua;", "and above every beast of the field;"], ["o lou manava o le a e sosolo ai,", "upon thy belly shalt thou go,"], ["ma o le efuefu o le a e 'ai i aso uma o lou ola;", "and dust shalt thou eat all the days of thy life;"]]},
  {num:21,words:[["Ma o le a Ou tuu le feitagai i le va o oe ma le fafine,", "And I will put enmity between thee and the woman,"], ["i le va o lau fanau ma lana fanau;", "between thy seed and her seed;"], ["ma o le a ia faamanu'a lou ulu,", "and he shall bruise thy head,"], ["ma o le a e faamanu'a lona mulivae.", "and thou shalt bruise his heel."]]},
  {num:22,words:[["I le fafine,", "Unto the woman,"], ["sa A'u fai atu i ai,", "I,"], ["o le Alii le Atua:", "the Lord God, said:"], ["O le a Ou matuā faateleina lou tiga ma lou ma'itaga O le a e fanau mai fanau ma le tiga ,", "I will greatly multiply thy sorrow and thy conception. In sorrow thou shalt bring forth children,"], ["ma o lou manao o le a ua'i atu i lau tane,", "and thy desire shall be to thy husband ,"], ["ma o le a pule o ia i ou luga.", "and he shall rule over thee."]]},
  {num:23,words:[["Ma ia Atamu,", "And unto Adam,"], ["o A'u,", "I,"], ["o le Alii le Atua,", "the Lord God,"], ["na fai atu i ai:", "said:"], ["Ona sa e faalogo i le leo o lau ava,", "Because thou hast hearkened unto the voice of thy wife,"], ["ma 'ai i le fua o le laau na Ou poloaiina oe,", "and hast eaten of the fruit of the tree of which I commanded thee,"], ["e faapea—Aua e te 'ai ai,", "saying—Thou shalt not eat of it,"], ["o le a fetuuina le eleele ona o oe;", "cursed shall be the ground for thy sake;"], ["o le tiga o le a e 'ai mai ai i aso uma o lou ola.", "in sorrow shalt thou eat of it all the days of thy life."]]},
  {num:24,words:[["O laau tuitui foi,", "Thorns also,"], ["ma laau talatala o le a ia aumai ia te oe,", "and thistles shall it bring forth to thee,"], ["ma o le a e 'ai laau afu o le fanua.", "and thou shalt eat the herb of the field."]]},
  {num:25,words:[["O le a e 'ai ai au meaai afu o ou mata,", "By the sweat of thy face shalt thou eat bread,"], ["seia e toe foi i le eleele—aua o le a e oti lava—ona o le eleele na aumai ai oe:", "until thou shalt return unto the ground—for thou shalt surely die—for out of it wast thou taken:"], ["o le efuefu oe,", "for dust thou wast,"], ["ma o le a e toe foi lava i le efuefu.", "and unto dust shalt thou return."]]},
  {num:26,words:[["Ma sa faaigoa e Atamu lana ava o Eva,", "And Adam called his wife’s name Eve,"], ["aua o ia o le tinā o tagata ola uma;", "because she was the mother of all living;"], ["ona sa faapea ona faaigoa e A'u,", "for thus have I,"], ["o le Alii le Atua,", "the Lord God,"], ["le uluai fafine o fafine uma,", "called the first of all women,"], ["e toatele .", "which are many ."]]},
  {num:27,words:[["Ma sa faia e A'u,", "Unto Adam,"], ["o le Alii le Atua,", "and also unto his wife,"], ["ofu pa'u manu,", "did I, the Lord God,"], ["mo Atamu ma lana ava foi,", "make coats of skins ,"], ["ma faaofu ai i laua.", "and clothed them."]]},
  {num:28,words:[["Ma o A'u,", "And I,"], ["o le Alii le Atua,", "the Lord God,"], ["na fai atu i la'u Toatasi na Fanaua:", "said unto mine Only Begotten:"], ["Faauta,", "Behold,"], ["ua avea le tagata e pei o se tasi o i tatou e iloa le lelei ma le leaga;", "the man is become as one of us to know good and evil;"], ["ma o lenei ne'i tuu atu lona lima ma 'ai foi i le laau o le ola,", "and now lest he put forth his hand and partake also of the tree of life ,"], ["ma 'ai ma ola ai e faavavau,", "and eat and live forever,"]]},
  {num:29,words:[["O lea,", "Therefore I,"], ["o A'u,", "the Lord God,"], ["o le Alii le Atua, o le a auina ese atu o ia mai le Faatoaga o Etena ,", "will send him forth from the Garden of Eden ,"], ["e galueaiina le eleele na aumai ai o ia;", "to till the ground from whence he was taken;"]]},
  {num:30,words:[["Auā e pei ona ola A'u,", "For as I,"], ["o le Alii le Atua,", "the Lord God,"], ["ua faapea foi ona lē mafai ona foi aunoa mai a'u 'upu ,", "liveth, even so my words cannot return void,"], ["ona e pei ona o atu i latou mai lo'u gutu o le a faapea lava ona faataunuuina i latou.", "for as they go forth out of my mouth they must be fulfilled."]]},
  {num:31,words:[["O lea na Ou tuli ese ai i fafo le tagata,", "So I drove out the man,"], ["ma sa Ou tuu i le itu i sasa'e o le Faatoaga o Etena,", "and I placed at the east of the Garden of Eden ,"], ["kerupi ma se pelu afi mumu,", "cherubim and a flaming sword,"], ["sa feliuliuai i itu uma e leoleo le ala o le laau o le ola.", "which turned every way to keep the way of the tree of life."]]},
  {num:32,words:[["(Ma o upu nei na Ou tautala atu ai i la'u auauna o Mose,", "(And these are the words which I spake unto my servant Moses,"], ["ma ua moni i latou e pei lava ona Ou loto i ai;", "and they are true even as I will;"], ["ma ua Ou tautala atu i latou ia te oe.", "and I have spoken them unto you."], ["Vaai ia e lē faaalia atu i latou i se tagata,", "See thou show them unto no man, until I command you,"], ["vagana ia i latou o e e talitonu.", "except to them that believe."], ["Amene.)", "Amen.)"]]},
];
renderVerseSet(ms_ch_4_Verses, 'ms-ch4-verses');

var ms_ch_5_Verses = [
  {num:1,words:[["Ma sa oo ina ua mavae ona tutuli ese o i laua e A'u,", "And it came to pass that after I,"], ["o le Ali'i le Atua,", "the Lord God,"], ["sa amata ona galueaiina e Atamu le eleele,", "had driven them out, that Adam began to till the earth,"], ["ma pule i luga o manu vaefa uma o le fanua,", "and to have dominion over all the beasts of the field,"], ["ma 'ai ana meaai ma le afu o lona muaulu,", "and to eat his bread by the sweat of his brow ,"], ["e pei ona poloaiina ai o ia e A'u o le Alii.", "as I the Lord had commanded him."], ["Ma sa galue foi Eva,", "And Eve,"], ["lana ava,", "also, his wife,"], ["faatasi ma ia.", "did labor with him."]]},
  {num:2,words:[["Ma sa iloa e Atamu lana ava,", "And Adam knew his wife,"], ["ma sa fanauina e ia ia te ia o atalii ma afafine ,", "and she bare unto him sons and daughters ,"], ["ma sa amata ona latou fanafanau ma uluola i le lalolagi.", "and they began to multiply and to replenish the earth."]]},
  {num:3,words:[["Ma mai le taimi lena i luma,", "And from that time forth,"], ["sa amata ona vaevae taitoalua o atalii ma afafine o Atamu i le laueleele,", "the sons and daughters of Adam began to divide two and two in the land,"], ["ma e galueaiina le laueleele,", "and to till the land,"], ["ma tausi lafu manu,", "and to tend flocks,"], ["ma sa latou fananauina foi atalii ma afafine.", "and they also begat sons and daughters."]]},
  {num:4,words:[["Ma o Atamu ma Eva,", "And Adam and Eve,"], ["lana ava,", "his wife,"], ["sa valaau atu i le suafa o le Alii,", "called upon the name of the Lord,"], ["ma sa laua faalogoina le siufofoga o le Alii mai le ala agai i le Faatoaga o Etena ,", "and they heard the voice of the Lord from the way toward the Garden of Eden ,"], ["ua fetalai mai ia i laua,", "speaking unto them,"], ["ae sa laua lē vaai atu ia te ia;", "and they saw him not;"], ["aua sa punitia ese i laua mai ona luma .", "for they were shut out from his presence ."]]},
  {num:5,words:[["Ma sa tuu mai e ia ia i laua poloaiga,", "And he gave unto them commandments,"], ["ia la ifo atu i le Alii lo laua Atua,", "that they should worship the Lord their God,"], ["ma avatu uluai manu o a laua lafu,", "and should offer the firstlings of their flocks ,"], ["mo se taulaga i le Alii. Ma sa usiusitai Atamu i poloaiga a le Alii.", "for an offering unto the Lord. And Adam was obedient unto the commandments of the Lord."]]},
  {num:6,words:[["Ma ina ua mavae aso e tele,", "And after many days an angel of the Lord appeared unto Adam,"], ["sa oo mai se agelu a le Alii ia Atamu,", "saying:"], ["ua fetalai mai: Aisea ua e osi atu ai taulaga i le Alii? Ma sa fai atu Atamu ia te ia:", "Why dost thou offer sacrifices unto the Lord? And Adam said unto him:"], ["Ou te lē iloa,", "I know not,"], ["ae na poloaiina ai a'u e le Alii.", "save the Lord commanded me."]]},
  {num:7,words:[["Ma ona feitalai mai lea o le agelu,", "And then the angel spake,"], ["e faapea mai:", "saying:"], ["O lenei mea o se faatusa lea o le taulaga a le Toatasi na Fanaua e le Tamā,", "This thing is a similitude of the sacrifice of the Only Begotten of the Father,"], ["o lē ua tumu i le alofa tunoa ma le upumoni.", "which is full of grace and truth ."]]},
  {num:8,words:[["O le mea lea,", "Wherefore,"], ["ia e faia mea uma e te faia i le suafa o le Alo,", "thou shalt do all that thou doest in the name of the Son,"], ["ma ia e salamo ma valaau atu i le Atua i le suafa o le Alo e faavavau.", "and thou shalt repent and call upon God in the name of the Son forevermore."]]},
  {num:9,words:[["Ma i lena aso na pa'ū ifo ai i luga o Atamu le Agaga Paia,", "And in that day the Holy Ghost fell upon Adam,"], ["o lē e molimau i le Tamā ma le Alo,", "which beareth record of the Father and the Son,"], ["ua fetalai mai:", "saying:"], ["O A'u o le Toatasi na Fanaua e le Tamā mai le amataga,", "I am the Only Begotten of the Father from the beginning,"], ["mai le taimi nei i luma ma le faavavau,", "henceforth and forever,"], ["aua talu ai ona ua e pa'ū ia mafai ona laveaiina oe,", "that as thou hast fallen thou mayest be redeemed ,"], ["ma tagata uma,", "and all mankind,"], ["le toatele lava e mananao i ai.", "even as many as will."]]},
  {num:10,words:[["Ma i lena aso na viia ai e Atamu le Atua ma sa faatumuina ,", "And in that day Adam blessed God and was filled ,"], ["ma sa amata ona vavalo e uiga i aiga uma o le lalolagi,", "and began to prophesy concerning all the families of the earth,"], ["ua fai mai:", "saying:"], ["Ia viia lava le suafa o le Atua,", "Blessed be the name of God,"], ["aua ona o la'u solitulafono ua pupula ai o'u mata,", "for because of my transgression my eyes are opened,"], ["ma o le a ou maua i le olaga lenei le olioli ,", "and in this life I shall have joy ,"], ["ma o le a ou toe vaai i le Atua i le tino .", "and again in the flesh I shall see God."]]},
  {num:11,words:[["Ma o Eva ,", "And Eve,"], ["lana ava,", "his wife,"], ["sa faalogo atu i nei mea uma ma sa fiafia,", "heard all these things and was glad,"], ["ua fai mai:", "saying:"], ["Ana lē seanoa la ta solitulafono po ua lē maua e i taua ni fanau ,", "Were it not for our transgression we never should have had seed ,"], ["ma po ua lē mafai ona ta iloa le lelei ma le leaga,", "and never should have known good and evil,"], ["ma le olioli o le togiolaina o i ta'ua,", "and the joy of our redemption,"], ["ma le ola e faavavau ua tuu mai e le Atua ia i latou uma o e e usiusitai.", "and the eternal life which God giveth unto all the obedient."]]},
  {num:12,words:[["Ma sa viia e Atamu ma Eva le suafa o le Atua,", "And Adam and Eve blessed the name of God,"], ["ma sa la faailoa atu mea uma i o laua atalii ma afafine.", "and they made all things known unto their sons and their daughters."]]},
  {num:13,words:[["Ona sau ai lea o Satani i totonu o i latou,", "And Satan came among them,"], ["ua fai mai:", "saying:"], ["O a'u foi o se atalii o le Atua;", "I am also a son of God;"], ["ma sa ia faatonu mai ia te i latou,", "and he commanded them,"], ["ua fai mai:", "saying:"], ["Aua tou te talitonu i ia mea;", "Believe it not;"], ["ma sa latou lē talitonu i ai,", "and they believed it not,"], ["ma sa sili atu lo latou alolofa ia Satani nai lo le Atua. Ma sa amata mai i le taimi lena ona faaletino ,", "and they loved Satan more than God. And men began from that time forth to be carnal ,"], ["nautino,", "sensual,"], ["ma faatiapolo tagata.", "and devilish."]]},
  {num:14,words:[["Ma sa valaau atu le Alii le Atua i tagata uma i soo se mea e ala i le Agaga Paia ma poloaiina i latou e ao ina latou salamo;", "And the Lord God called upon men by the Holy Ghost everywhere and commanded them that they should repent;"]]},
  {num:15,words:[["Ma o le toatele sa talitonu i le Alo,", "And as many as believed in the Son,"], ["ma salamo i a latou agasala,", "and repented of their sins,"], ["o le a faaolaina ;", "should be saved ;"], ["ma o le toatele sa lē talitonu ma lē salamo, o le a tausalaina ;", "and as many as believed not and repented not,"], ["ma sa tulei atu afioga mai le fofoga o le Atua i se poloaiga mau;", "should be damned ;"], ["o le mea lea,", "and the words went forth out of the mouth of God in a firm decree;"], ["o le a faataunuuina lava i latou.", "wherefore they must be fulfilled."]]},
  {num:16,words:[["Ma o Atamu ma Eva,", "And Adam and Eve,"], ["lana ava,", "his wife,"], ["sa lē tu'ua le valaau atu i le Atua. Ma sa iloa e Atamu lana ava o Eva,", "ceased not to call upon God. And Adam knew Eve his wife,"], ["ma sa to o ia ma fanauina Kaino ,", "and she conceived and bare Cain ,"], ["ma sa fai mai:", "and said:"], ["Ua ou maua se tama tane mai le Alii;", "I have gotten a man from the Lord;"], ["o le mea lea o le a lē mafai ai e ia ona teena ana afioga. Ae faauta,", "wherefore he may not reject his words. But behold,"], ["sa lē faalogo Kaino,", "Cain hearkened not,"], ["ua fai mai:", "saying:"], ["O ai le Alii e tatau ai ona ou iloa o ia?", "Who is the Lord that I should know him?"]]},
  {num:17,words:[["Ma sa toe to Eva ma fanauina lona uso o Apelu . Ma sa faalogo Apelu i le siufofoga o le Alii. Ma o Apelu sa leoleo mamoe,", "And she again conceived and bare his brother Abel. And Abel hearkened unto the voice of the Lord. And Abel was a keeper of sheep,"], ["ae o Kaino sa galueaiina le eleele.", "but Cain was a tiller of the ground."]]},
  {num:18,words:[["Ma sa sili atu le alofa o Kaino ia Satani nai lo le Atua. Ma sa faatonu o ia e Satani,", "And Cain loved Satan more than God. And Satan commanded him,"], ["ua fai atu:", "saying:"], ["Fai se taulaga i le Alii.", "Make an offering unto the Lord."]]},
  {num:19,words:[["Ma i le gasologa o le taimi, sa oo ina aumai e Kaino mai fua o le eleele se taulaga i le Alii.", "And in process of time it came to pass that Cain brought of the fruit of the ground an offering unto the Lord."]]},
  {num:20,words:[["Ma o Apelu,", "And Abel,"], ["sa aumai foi e ia mai ulua'i manu o lana lafu,", "he also brought of the firstlings of his flock,"], ["ma le ga'o o i ai. Ma sa aloaia e le Alii Apelu,", "and of the fat thereof. And the Lord had respect unto Abel,"], ["ma lana taulaga ;", "and to his offering ;"]]},
  {num:21,words:[["Ae o Kaino,", "But unto Cain,"], ["ma lana taulaga ,", "and to his offering ,"], ["sa lē aloaia e le Alii. O lenei sa iloa e Satani lenei mea,", "he had not respect. Now Satan knew this,"], ["ma sa fiafia i ai o ia. Ma sa ita tele Kaino,", "and it pleased him. And Cain was very wroth,"], ["ma sa faauu o ia.", "and his countenance fell."]]},
  {num:22,words:[["Ma sa fetalai mai le Alii ia Kaino:", "And the Lord said unto Cain:"], ["Aisea ua e ita ai? Aisea ua e faauu ai?", "Why art thou wroth? Why is thy countenance fallen?"]]},
  {num:23,words:[["Afai e te faia mea lelei,", "If thou doest well,"], ["e talia oe. Ma afai e te lē faia mea lelei,", "thou shalt be accepted . And if thou doest not well,"], ["ua taoto mai le agasala i le faitotoa,", "sin lieth at the door,"], ["ma ua manao Satani ia maua oe;", "and Satan desireth to have thee;"], ["ma vagana ua e faalogo mai i a'u poloaiga,", "and except thou shalt hearken unto my commandments,"], ["o le a Ou tuu atu oe,", "I will deliver thee up,"], ["ma o le a faia ia te oe e tusa ma lona manao. Ma o le a e pule ia ia;", "and it shall be unto thee according to his desire. And thou shalt rule over him;"]]},
  {num:24,words:[["Aua e mai le taimi nei i luma o le a avea oe ma tamā o ana pepelo;", "For from this time forth thou shalt be the father of his lies ;"], ["o le a ta'ua oe o le Malaia ;", "thou shalt be called Perdition ;"], ["aua sa e faapea foi ae le'i i ai le lalolagi.", "for thou wast also before the world."]]},
  {num:25,words:[["Ma o le a fai ane i taimi e oo mai—E faapea o nei mea inosia na mai ia Kaino;", "And it shall be said in time to come—That these abominations were had from Cain ;"], ["ona sa teena e ia le fautuaga sili na mai le Atua;", "for he rejected the greater counsel which was had from God;"], ["ma o se fetuu lenei o le a Ou tuu i luga o oe,", "and this is a cursing which I will put upon thee,"], ["vagana ai ua e salamo.", "except thou repent."]]},
  {num:26,words:[["Ma sa ita Kaino,", "And Cain was wroth,"], ["ma sa lē toe faalogo i le siufofoga o le Alii,", "and listened not any more to the voice of the Lord,"], ["pe ia Apelu,", "neither to Abel,"], ["lona uso,", "his brother,"], ["o lē na savali i le paia i luma o le Alii.", "who walked in holiness before the Lord."]]},
  {num:27,words:[["Ma sa faanoanoa Atamu ma lana ava i luma o le Alii,", "And Adam and his wife mourned before the Lord,"], ["ona o Kaino ma ona uso.", "because of Cain and his brethren."]]},
  {num:28,words:[["Ma sa oo ina ave e Kaino se tasi o afafine o ona uso ma ana ava,", "And it came to pass that Cain took one of his brothers’ daughters to wife ,"], ["ma sa sili atu lo laua alolofa ia Satani nai lo le Atua.", "and they loved Satan more than God."]]},
  {num:29,words:[["Ma sa fai atu Satani ia Kaino:", "And Satan said unto Cain:"], ["Tauto mai ia te a'u i lou faai,", "Swear unto me by thy throat,"], ["ma afai e te ta'ua o le a e oti;", "and if thou tell it thou shalt die;"], ["ma ia faatauto ou uso i o latou ulu,", "and swear thy brethren by their heads,"], ["ma i le Atua soifua,", "and by the living God,"], ["ia latou le ta'ua;", "that they tell it not;"], ["ona afai latou te ta'ua,", "for if they tell it,"], ["o le a latou feoti lava;", "they shall surely die;"], ["ma o lenei ina ia lē iloa e lou tamā;", "and this that thy father may not know it;"], ["ma o le aso nei o le a ou tuu atu ai lou uso o Apelu i ou lima.", "and this day I will deliver thy brother Abel into thine hands."]]},
  {num:30,words:[["Ma sa tauto Satani ia Kaino o le a faia e ia e tusa ma ana poloai. Ma o nei mea uma sa faia i le faalilolilo.", "And Satan sware unto Cain that he would do according to his commands . And all these things were done in secret."]]},
  {num:31,words:[["Ma sa fai mai Kaino:", "And Cain said:"], ["E moni lava o a'u o Mahana,", "Truly I am Mahan,"], ["o le pule o lenei mealilo tele,", "the master of this great secret ,"], ["ina ia mafai ona ou fasioti ma maua mea. O le mea lea na ta'ua ai Kaino o Mahana Pule,", "that I may murder and get gain . Wherefore Cain was called Master Mahan ,"], ["ma sa mitamita o ia i lona amioleaga.", "and he gloried in his wickedness."]]},
  {num:32,words:[["Ma sa alu atu Kaino i le fanua,", "And Cain went into the field,"], ["ma sa talanoa Kaino ma Apelu,", "and Cain talked with Abel,"], ["lona uso. Ma sa oo a'o i ai i laua i le fanua,", "his brother. And it came to pass that while they were in the field,"], ["sa tu atu Kaino e faasaga ia Apelu,", "Cain rose up against Abel,"], ["lona uso,", "his brother,"], ["ma fasioti ia te ia.", "and slew him."]]},
  {num:33,words:[["Ma sa mitamita Kaino i le mea ua ia faia,", "And Cain gloried in that which he had done,"], ["ua fai mai:", "saying:"], ["Ua ou saoloto;", "I am free;"], ["ua pauu moni mai lava lafu a lo'u uso i o'u lima.", "surely the flocks of my brother falleth into my hands."]]},
  {num:34,words:[["Ma sa fetalai mai le Alii ia Kaino:", "And the Lord said unto Cain:"], ["O fea Apelu,", "Where is Abel,"], ["lou uso? Ma sa fai atu o ia:", "thy brother? And he said:"], ["Ou te lē iloa. O a'u ea o se leoleo o lo'u uso?", "I know not. Am I my brother’s keeper ?"]]},
  {num:35,words:[["Ma sa fetalai mai le Alii:", "And the Lord said:"], ["O le a le mea ua e faia? Ua tagi mai ia te a'u le leo o le toto o lou uso mai le eleele.", "What hast thou done? The voice of thy brother’s blood cries unto me from the ground."]]},
  {num:36,words:[["Ma o lenei o le a fetuuina oe mai le eleele ua faamaga mai lona gutu e tali le toto o lou uso mai lou lima.", "And now thou shalt be cursed from the earth which hath opened her mouth to receive thy brother’s blood from thy hand."]]},
  {num:37,words:[["A e galueaiina le eleele o le a lē tuu mai e ia ia te oe lona malosi mai le taimi nei i luma. O le a avea oe o se tagata solasola ma maumausolo i le lalolagi.", "When thou tillest the ground it shall not henceforth yield unto thee her strength . A fugitive and a vagabond shalt thou be in the earth."]]},
  {num:38,words:[["Ma sa fai atu Kaino i le Alii:", "And Cain said unto the Lord:"], ["Sa faaosoosoina a'u e Satani ona o lafu a lo'u uso. Ma sa ou ita foi;", "Satan tempted me because of my brother’s flocks. And I was wroth also;"], ["ona sa e talia lana taulaga ae lē o la'u;", "for his offering thou didst accept and not mine;"], ["ua tele atu lo'u faasalaga nai lo le mea ou te lavatia.", "my punishment is greater than I can bear."]]},
  {num:39,words:[["Faauta ua e tuli ese a'u i fafo i le aso nei mai luma o fofoga o le Alii,", "Behold thou hast driven me out this day from the face of the Lord,"], ["ma o le a natia a'u mai i ou fofoga;", "and from thy face shall I be hid;"], ["ma o le a avea a'u ma tagata solasola ma maumausolo i le lalolagi;", "and I shall be a fugitive and a vagabond in the earth; and it shall come to pass,"], ["ma o le a oo mai foi o ia o lē e mauaina a'u o le a fasioti ia te a'u,", "that he that findeth me will slay me,"], ["ona o a'u amioletonu,", "because of mine iniquities,"], ["ona o ia mea ua lē natia mai le Alii.", "for these things are not hid from the Lord."]]},
  {num:40,words:[["Ma o A'u o le Alii na fai atu ia te ia:", "And I the Lord said unto him:"], ["Ai se e fasioti ia te oe,", "Whosoever slayeth thee,"], ["o le a faafitu ona tauimasui ia te ia. Ma o A'u o le Alii sa tuuina se faailoga i luga o Kaino,", "vengeance shall be taken on him sevenfold. And I the Lord set a mark upon Cain,"], ["ne'i fasioti o ia e se e maua o ia.", "lest any finding him should kill him."]]},
  {num:41,words:[["Ma sa tapunia ese Kaino mai luma o le Alii,", "And Cain was shut out from the presence of the Lord,"], ["ma sa mau faatasi ma lana ava ma le toatele o ona uso i le laueleele o Nota,", "and with his wife and many of his brethren dwelt in the land of Nod,"], ["i le itu i sasa'e o Etena.", "on the east of Eden."]]},
  {num:42,words:[["Ma sa iloa e Kaino lana ava,", "And Cain knew his wife,"], ["ma sa to o ia ma fanauina Enoka,", "and she conceived and bare Enoch,"], ["ma sa fanauina foi e ia atalii ma afafine e toatele. Ma sa fausia e ia se aai,", "and he also begat many sons and daughters. And he builded a city,"], ["ma sa ta'u e ia le igoa o le aai i le igoa o lona atalii,", "and he called the name of the city after the name of his son,"], ["o Enoka.", "Enoch."]]},
  {num:43,words:[["Ma sa fanauina ia Enoka Irata,", "And unto Enoch was born Irad,"], ["ma isi atalii ma afafine. Ma sa fanaua e Irata Mekuala,", "and other sons and daughters. And Irad begat Mahujael,"], ["ma isi atalii ma afafine. Ma sa fanaua e Mekuala Metusaeli,", "and other sons and daughters. And Mahujael begat Methusael,"], ["ma isi atalii ma afafine. Ma sa fanaua e Metusaeli o Lameko.", "and other sons and daughters. And Methusael begat Lamech."]]},
  {num:44,words:[["Ma sa ave e Lameko ia te ia ni ava e toalua;", "And Lamech took unto himself two wives;"], ["o le igoa o le tasi o Ata,", "the name of one being Adah,"], ["ma o le igoa o le isi,", "and the name of the other,"], ["o Sela.", "Zillah."]]},
  {num:45,words:[["Ma sa fanaua e Ata Iapalu;", "And Adah bare Jabal;"], ["o ia o le tamā o e e mau i faleie,", "he was the father of such as dwell in tents ,"], ["ma sa avea i latou ma tagata tausi manu faatoaga;", "and they were keepers of cattle;"], ["ma o le igoa o lona uso o Iupalu,", "and his brother’s name was Jubal,"], ["o lē o le tamā o i latou uma o e ta kitara ma faaili.", "who was the father of all such as handle the harp and organ."]]},
  {num:46,words:[["Ma o Sela,", "And Zillah,"], ["sa fanauaina foi e ia Tupalu Kaino,", "she also bare Tubal Cain,"], ["o se tufuga o mea uma e fai i apamemea ma le u'amea. Ma o le tuafafine o Tupalu Kaino o Naama.", "an instructor of every artificer in brass and iron. And the sister of Tubal Cain was called Naamah."]]},
  {num:47,words:[["Ma sa fai atu Lameko i ana ava,", "And Lamech said unto his wives,"], ["o Ata ma Sela:", "Adah and Zillah:"], ["Faalogo mai i lo'u leo,", "Hear my voice,"], ["oulua ava a Lameko,", "ye wives of Lamech,"], ["faalogo mai i la'u tautala atu;", "hearken unto my speech;"], ["ona ua ou fasiotia se tagata i lo'u manu'a,", "for I have slain a man to my wounding,"], ["ma o se taule'ale'a i lo'u tiga.", "and a young man to my hurt."]]},
  {num:48,words:[["Afai e faafitu ona tauimasui o Kaino,", "If Cain shall be avenged sevenfold,"], ["e moni o Lameko o le a faafitugafulu ma le fitu;", "truly Lamech shall be seventy and seven fold ;"]]},
  {num:49,words:[["Ona sa ulu atu Lameko i se feagaiga ma Satani,", "For Lamech having entered into a covenant with Satan,"], ["e pei ona faia e Kaino,", "after the manner of Cain,"], ["lea na avea ai o ia ma Mahana Pule,", "wherein he became Master Mahan,"], ["o le pule o lena mealilo tele na tuuina mai e Satani ia Kaino;", "master of that great secret which was administered unto Cain by Satan;"], ["ma o Irata,", "and Irad,"], ["le atalii o Enoka,", "the son of Enoch,"], ["ina ua iloa e ia la latou mealilo,", "having known their secret,"], ["sa amata ona faaali atu e ia i atalii o Atamu;", "began to reveal it unto the sons of Adam;"]]},
  {num:50,words:[["O le mea lea,", "Wherefore Lamech,"], ["ona o le ita,", "being angry,"], ["na fasioti ai e Lameko o ia,", "slew him,"], ["e lē pei ona faia e Kaino,", "not like unto Cain,"], ["i lona uso o Apelu,", "his brother Abel,"], ["ina ia maua ai mea;", "for the sake of getting gain,"], ["ae sa fasioti e Lameko Irata ona o le tautoga.", "but he slew him for the oath’s sake."]]},
  {num:51,words:[["Ona,", "For,"], ["mai lea i aso o Kaino,", "from the days of Cain,"], ["sa i ai se pulega faalilolilo,", "there was a secret combination ,"], ["ma o a latou galuega sa faia i le pouliuli,", "and their works were in the dark,"], ["ma sa latou iloa tagata taitoatasi o o latou uso.", "and they knew every man his brother."]]},
  {num:52,words:[["O le mea lea na fetuu ai Lameko e le Alii,", "Wherefore the Lord cursed Lamech,"], ["ma lona fale,", "and his house,"], ["ma i latou uma o e na osifeagaiga ma Satani;", "and all them that had covenanted with Satan;"], ["ona sa latou lē tausia poloaiga a le Atua,", "for they kept not the commandments of God,"], ["ma sa lē fiafia ai le Atua,", "and it displeased God,"], ["ma sa lē auauna mai o ia ia te i latou,", "and he ministered not unto them,"], ["ma o a latou galuega sa o ni mea inosia ia,", "and their works were abominations,"], ["ma sa amata ona sosolo atu i totonu o atalii uma o tagata. Ma sa i ai ia mea i totonu o atalii o tagata.", "and began to spread among all the sons of men. And it was among the sons of men."]]},
  {num:53,words:[["Ma o ia mea sa lē tautalaina i totonu o afafine o tagata,", "And among the daughters of men these things were not spoken,"], ["ona sa ta'u e Lameko le mealilo i ana ava,", "because that Lamech had spoken the secret unto his wives,"], ["ma sa la'ua fouvale e faasaga ia te ia,", "and they rebelled against him,"], ["ma ta'u atu ia mea i le lautele,", "and declared these things abroad,"], ["ma sa lē i ai le agaalofa;", "and had not compassion;"]]},
  {num:54,words:[["O le mea lea na inosia ai Lameko,", "Wherefore Lamech was despised,"], ["ma tuli ese i fafo,", "and cast out,"], ["ma lē sau ai i totonu o atalii o tagata,", "and came not among the sons of men,"], ["ne'i oti o ia.", "lest he should die."]]},
  {num:55,words:[["Ma sa faapea ona amata ona sosolo o galuega o le pouliuli i totonu o atalii uma o tagata.", "And thus the works of darkness began to prevail among all the sons of men."]]},
  {num:56,words:[["Ma sa fetuu e le Atua le lalolagi i se fetuu tiga,", "And God cursed the earth with a sore curse,"], ["ma sa toatama'i i e amioleaga,", "and was angry with the wicked,"], ["atoa ma atalii uma o tagata o e na faia e ia;", "with all the sons of men whom he had made;"]]},
  {num:57,words:[["Aua sa latou lē faalogo i lona siufofoga,", "For they would not hearken unto his voice,"], ["pe talitonu i lona Alo e Toatasi na Fanaua,", "nor believe on his Only Begotten Son,"], ["o ia lava na ia folafola mai o le a afio mai i le meritiana o taimi,", "even him whom he declared should come in the meridian of time,"], ["o lē na saunia mai luma atu o le faavaega o le lalolagi.", "who was prepared from before the foundation of the world."]]},
  {num:58,words:[["Ma sa faapea ona amata ona talai atu o le Talalelei ,", "And thus the Gospel began to be preached ,"], ["mai le amataga,", "from the beginning,"], ["ua folafola atu e agelu paia ua auina atu mai luma o le Atua,", "being declared by holy angels sent forth from the presence of God,"], ["ma i lona lava siufofoga,", "and by his own voice,"], ["ma i le meaalofa o le Agaga Paia.", "and by the gift of the Holy Ghost."]]},
  {num:59,words:[["Ma sa faapea ona faamautuina o mea uma ia Atamu,", "And thus all things were confirmed unto Adam ,"], ["i se sauniga paia,", "by an holy ordinance,"], ["ma talai atu ai le Talalelei,", "and the Gospel preached,"], ["ma auina atu se poloaiga,", "and a decree sent forth,"], ["e tatau ona i ai i le lalolagi,", "that it should be in the world,"], ["seia oo i lona iuga;", "until the end thereof;"], ["ma sa faapea lava. Amene.", "and thus it was. Amen."]]},
];
renderVerseSet(ms_ch_5_Verses, 'ms-ch5-verses');

var ms_ch_6_Verses = [
  {num:1,words:[["Ma sa faalogo Atamu i le siufofoga o le Atua,", "And Adam hearkened unto the voice of God,"], ["ma sa valaau atu i ona atalii ia salamo.", "and called upon his sons to repent."]]},
  {num:2,words:[["Ma sa toe iloa e Atamu lana ava,", "And Adam knew his wife again,"], ["ma sa fanauina e ia se atalii,", "and she bare a son,"], ["ma sa ta'u e Atamu lona igoa o Setu . Ma sa viia e Atamu le suafa o le Atua;", "and he called his name Seth . And Adam glorified the name of God;"], ["ona sa fai mai o ia:", "for he said:"], ["Ua tofia mai e le Atua ia te a'u se tasi atalii,", "God hath appointed me another seed,"], ["i le tulaga o Apelu,", "instead of Abel,"], ["o lē na fasiotia e Kaino.", "whom Cain slew."]]},
  {num:3,words:[["Ma sa faaali mai e le Atua o ia lava ia Setu,", "And God revealed himself unto Seth ,"], ["ma sa lē fouvale o ia,", "and he rebelled not,"], ["ae sa tuuina atu e ia se taulaga na talia,", "but offered an acceptable sacrifice ,"], ["e pei o lona uso o Apelu. Ma sa fanau mai foi ia te ia se atalii,", "like unto his brother Abel. And to him also was born a son,"], ["ma sa ta'u e ia lona igoa o Enosa.", "and he called his name Enos."]]},
  {num:4,words:[["Ma ona amata lea ona valaau atu o nei alii i le suafa o le Alii,", "And then began these men to call upon the name of the Lord,"], ["ma sa faamanuiaina i latou e le Alii;", "and the Lord blessed them;"]]},
  {num:5,words:[["Ma sa tausia se tusi faamanatu,", "And a book of remembrance was kept,"], ["lea sa tusia ai i le gagana a Atamu,", "in the which was recorded, in the language of Adam,"], ["ona sa tuuina mai i le toatele na valaau atu i le Atua e tusitusi e ala i le agaga o musumusuga ;", "for it was given unto as many as called upon God to write by the spirit of inspiration ;"]]},
  {num:6,words:[["Ma o i latou na aoaoina a latou fanau e faitau ma tusitusi,", "And by them their children were taught to read and write,"], ["i se gagana na mamā ma lē eleelea.", "having a language which was pure and undefiled."]]},
  {num:7,words:[["O lenei o lea lava Perisitua ,", "Now this same Priesthood ,"], ["lea sa i ai i le amataga,", "which was in the beginning,"], ["o le a i ai foi i le iuga o le lalolagi.", "shall be in the end of the world also."]]},
  {num:8,words:[["Ma o le valoaga lenei na fofogaina e Atamu,", "Now this prophecy Adam spake,"], ["a'o uunaia o ia e le Agaga Paia,", "as he was moved upon by the Holy Ghost ,"], ["ma sa tausia se gafa o le fanau a le Atua. Ma o le tusi lenei o augatupulaga a Atamu,", "and a genealogy was kept of the children of God. And this was the book of the generations of Adam,"], ["ua fai mai:", "saying:"], ["I le aso na foafoa ai e le Atua le tagata,", "In the day that God created man,"], ["na faia ai e ia o ia i le faatusa o le Atua;", "in the likeness of God made he him;"]]},
  {num:9,words:[["O le faatusa o lona lava tino,", "In the image of his own body ,"], ["o le tane ma le fafine,", "male and female,"], ["na foafoa ai e ia i laua ,", "created he them,"], ["ma faamanuia ia te i laua,", "and blessed them,"], ["ma ta'ua lo laua igoa o Atamu,", "and called their name Adam,"], ["i le aso na foafoa ai i laua ma avea ai ma tagata ola i luga o le laueleele o le tuuvae o le Atua.", "in the day when they were created and became living souls in the land upon the footstool of God."]]},
  {num:10,words:[["Ma sa ola Atamu i le selau tolugafulu o tausaga,", "And Adam lived one hundred and thirty years,"], ["ma fanaua se atalii i lona lava faatusa,", "and begat a son in his own likeness,"], ["i ona lava foliga ,", "after his own image ,"], ["ma ta'ua lona igoa o Setu.", "and called his name Seth."]]},
  {num:11,words:[["Ma o aso o Atamu,", "And the days of Adam,"], ["ina ua uma ona fanaua e ia Setu,", "after he had begotten Seth,"], ["e valu selau tausaga,", "were eight hundred years,"], ["ma sa fanaua e ia atalii ma afafine e toatele;", "and he begat many sons and daughters;"]]},
  {num:12,words:[["Ma o aso uma na ola ai Atamu e iva selau ma le tolusefulu tausaga,", "And all the days that Adam lived were nine hundred and thirty years,"], ["ma sa maliu o ia.", "and he died."]]},
  {num:13,words:[["Sa ola Setu i le selau ma le lima o tausaga,", "Seth lived one hundred and five years,"], ["ma fanaua Enosa,", "and begat Enos,"], ["ma sa vavalo i ona aso uma,", "and prophesied in all his days,"], ["ma aoao i lona atalii o Enosa ala o le Atua;", "and taught his son Enos in the ways of God;"], ["o le mea lea na vavalo ai foi Enosa.", "wherefore Enos prophesied also."]]},
  {num:14,words:[["Ma sa ola Setu,", "And Seth lived,"], ["ina ua uma ona fanaua e ia Enosa,", "after he begat Enos,"], ["i tausaga e valu selau ma le fitu,", "eight hundred and seven years,"], ["ma fanaua ni atalii ma afafine e toatele.", "and begat many sons and daughters."]]},
  {num:15,words:[["Ma sa toatele le fanauga a tagata i luga o le laueleele atoa. Ma i aso na sa i ai se puleaga tele a Satani i totonu o tagata,", "And the children of men were numerous upon all the face of the land. And in those days Satan had great dominion among men,"], ["ma sa sasao i o latou loto;", "and raged in their hearts;"], ["ma mai le taimi lena i luma na oo mai ai taua ma le faamasaatoto;", "and from thenceforth came wars and bloodshed;"], ["ma sa sii atu le lima o le tagata i lona lava uso,", "and a man’s hand was against his own brother,"], ["e fasioti,", "in administering death,"], ["ona o galuega faalilolilo,", "because of secret works ,"], ["i le sailiga o le pule.", "seeking for power ."]]},
  {num:16,words:[["O aso uma o Setu e iva selau ma le sefululua tausaga,", "All the days of Seth were nine hundred and twelve years,"], ["ma sa maliu o ia.", "and he died."]]},
  {num:17,words:[["Ma sa ola Enosa i tausaga e ivasefulu,", "And Enos lived ninety years,"], ["ma fanaua Kainano . Ma o Enosa ma e na totoe o le nuu o le Atua na o mai i fafo o le laueleele,", "and begat Cainan . And Enos and the residue of the people of God came out from the land,"], ["lea sa ta'ua o Sulona,", "which was called Shulon,"], ["ma nonofo i se laueleele o le folafolaga,", "and dwelt in a land of promise,"], ["lea sa ta'ua e ia i le igoa o lona lava atalii,", "which he called after his own son,"], ["o lē na faaigoa e ia o Kainano.", "whom he had named Cainan ."]]},
  {num:18,words:[["Ma sa ola Enosa,", "And Enos lived,"], ["ina ua uma ona fanaua e ia Kainano,", "after he begat Cainan,"], ["i tausaga e valu selau ma le sefululima,", "eight hundred and fifteen years,"], ["ma fanaua ni atalii ma afafine e toatele.", "and begat many sons and daughters."], ["Ma o aso uma o Enosa, e iva selau ma le lima tausaga,", "And all the days of Enos were nine hundred and five years,"], ["ma sa maliu o ia.", "and he died."]]},
  {num:19,words:[["Ma sa ola Kainano i tausaga e fitusefulu,", "And Cainan lived seventy years,"], ["ma fanaua Maalaelu;", "and begat Mahalaleel;"], ["ma sa ola Kainano ina ua uma ona fanaua e ia Maalaelu, i tausaga e valu selau fagafulu,", "and Cainan lived after he begat Mahalaleel eight hundred and forty years,"], ["ma fanaua atalii ma afafine.", "and begat sons and daughters."], ["Ma o aso uma o Kainano e iva selau ma le sefulu tausaga,", "And all the days of Cainan were nine hundred and ten years,"], ["ma sa maliu o ia.", "and he died."]]},
  {num:20,words:[["Ma sa ola Maalaelu i tausaga e onosefulu ma le lima,", "And Mahalaleel lived sixty-five years,"], ["ma fanaua Iareto;", "and begat Jared;"], ["ma sa ola Maalaelu,", "and Mahalaleel lived,"], ["ina ua uma ona fanaua e ia Iareto,", "after he begat Jared,"], ["i tausaga e valu selau ma le tolusefulu,", "eight hundred and thirty years,"], ["ma fanaua atalii ma afafine. Ma o aso uma o Maalaelu e valu selau ma le ivasefulu-lima tausaga,", "and begat sons and daughters. And all the days of Mahalaleel were eight hundred and ninety-five years,"], ["ma sa maliu o ia.", "and he died."]]},
  {num:21,words:[["Ma sa ola Iareto i tausaga e selau onosefulu-lua,", "And Jared lived one hundred and sixty-two years,"], ["ma fanaua Enoka ;", "and begat Enoch ;"], ["ma sa ola Iareto,", "and Jared lived,"], ["ina ua uma ona fanaua e ia Enoka,", "after he begat Enoch,"], ["i tausaga e valu selau,", "eight hundred years,"], ["ma fanaua atalii ma afafine. Ma sa aoao e Iareto ia Enoka i ala uma o le Atua.", "and begat sons and daughters. And Jared taught Enoch in all the ways of God."]]},
  {num:22,words:[["Ma o le gafa lenei o atalii o Atamu,", "And this is the genealogy of the sons of Adam, who was the son of God,"], ["o lē o le atalii o le Atua,", "with whom God,"], ["o lē na fetautalatalaai ma le Atua lava ia.", "himself, conversed."]]},
  {num:23,words:[["Ma sa o ni tagata talai o le amiotonu i latou,", "And they were preachers of righteousness ,"], ["ma sa tautatala ma vavalo atu,", "and spake and prophesied ,"], ["ma valaau atu i tagata uma,", "and called upon all men,"], ["i soo se mea lava,", "everywhere,"], ["ia salamo ;", "to repent;"], ["ma sa aoao atu le faatuatua i le fanauga a tagata.", "and faith was taught unto the children of men."]]},
  {num:24,words:[["Ma sa oo ina o aso uma o Iareto e iva selau ma le onosefulu-lua tausaga,", "And it came to pass that all the days of Jared were nine hundred and sixty-two years,"], ["ma sa maliu o ia.", "and he died."]]},
  {num:25,words:[["Ma sa ola Enoka i tausaga e onosefulu-lima,", "And Enoch lived sixty-five years,"], ["ma fanaua ai Metusela .", "and begat Methuselah."]]},
  {num:26,words:[["Ma sa oo ina malaga atu Enoka i le laueleele,", "And it came to pass that Enoch journeyed in the land,"], ["i totonu o le nuu;", "among the people;"], ["ma a'o malaga atu o ia,", "and as he journeyed,"], ["sa afio ifo le Agaga o le Atua mai le lagi,", "the Spirit of God descended out of heaven,"], ["ma afio i ona luga.", "and abode upon him."]]},
  {num:27,words:[["Ma sa faalogoina e ia se leo mai le lagi,", "And he heard a voice from heaven,"], ["ua fetalai mai:", "saying:"], ["Enoka,", "Enoch ,"], ["lo'u atalii e,", "my son,"], ["vavalo atu i lenei nuu,", "prophesy unto this people,"], ["ma fai atu ia te i latou—Ia salamo,", "and say unto them—Repent,"], ["ona ua faapea ona fetalai mai o le Alii:", "for thus saith the Lord:"], ["Ua Ou ita i lenei nuu,", "I am angry with this people,"], ["ma ua mumū a'e lo'u ita tele e faasaga ia te i latou;", "and my fierce anger is kindled against them;"], ["ona ua solo malo o latou loto,", "for their hearts have waxed hard ,"], ["ma ua feū o latou taliga e faalogo,", "and their ears are dull of hearing,"], ["ma ua lē mafai ona vaai mamao o latou mata;", "and their eyes cannot see afar off;"]]},
  {num:28,words:[["Ma i le tele o nei augatupulaga,", "And for these many generations,"], ["talu mai lava le aso na Ou foafoaina ai i latou,", "ever since the day that I created them,"], ["ua latou o sese ai,", "have they gone astray,"], ["ma teena a'u,", "and have denied me,"], ["ma latou saili ai a latou lava taupulepulega i le pouliuli;", "and have sought their own counsels in the dark;"], ["ma ua latou fuafuaina le fasioti tagata i a latou lava mea inosia,", "and in their own abominations have they devised murder,"], ["ma ua latou lē tausia poloaiga,", "and have not kept the commandments,"], ["ia sa Ou tuu atu i lo latou tamā,", "which I gave unto their father,"], ["o Atamu.", "Adam."]]},
  {num:29,words:[["O le mea lea,", "Wherefore,"], ["ua latou molimau pepelo ai i latou lava,", "they have foresworn themselves,"], ["ma,", "and,"], ["ua latou aumai i luga o i latou lava,", "by their oaths,"], ["ia latou tautoga le oti;", "they have brought upon themselves death;"], ["ma ua Ou saunia se seoli mo i latou,", "and a hell I have prepared for them,"], ["pe afai latou te lē salamo;", "if they repent not;"]]},
  {num:30,words:[["Ma o se tulafono lenei,", "And this is a decree,"], ["mai lo'u lava gutu,", "which I have sent forth in the beginning of the world,"], ["sa Ou auina atu i le amataga o le lalolagi,", "from my own mouth,"], ["mai lona faavaega,", "from the foundation thereof,"], ["ma o fofoga o a'u auauna,", "and by the mouths of my servants,"], ["ou tamā,", "thy fathers,"], ["na Ou poloaiina ai,", "have I decreed it,"], ["e pei lava ona o le a auina atu i le lalolagi,", "even as it shall be sent forth in the world,"], ["seia oo atu i ona tuluiga.", "unto the ends thereof."]]},
  {num:31,words:[["Ma ina ua faalogo Enoka i nei upu,", "And when Enoch had heard these words,"], ["sa ifo o ia lava i le eleele,", "he bowed himself to the earth,"], ["i luma o le Alii,", "before the Lord,"], ["ma tautala atu i luma o le Alii,", "and spake before the Lord,"], ["ua fai atu: Aisea ua amanaia ai a'u i lau silafaga,", "saying:"], ["ma o a'u ua nao se tama,", "Why is it that I have found favor in thy sight,"], ["ma ua inoino mai tagata uma ia te a'u;", "and am but a lad,"], ["ona e amu la'u tautala;", "and all the people hate me;"], ["o lea,", "for I am slow of speech;"], ["aisea ua avea ai a'u ma au auauna?", "wherefore am I thy servant?"]]},
  {num:32,words:[["Ma sa fetalai mai le Alii ia Enoka:", "And the Lord said unto Enoch:"], ["Alu atu ma fai e pei ona Ou poloaiina ai oe,", "Go forth and do as I have commanded thee,"], ["ma e leai se tagata o le a atia oe. Tatala lou gutu ,", "and no man shall pierce thee. Open thy mouth ,"], ["ma o le a faatumuina,", "and it shall be filled,"], ["ma o le a Ou tuu atu ia te oe upu e te tautala ai,", "and I will give thee utterance,"], ["aua ua i o'u lima tagata uma,", "for all flesh is in my hands,"], ["ma o le a Ou faia e pei ona foliga lelei mai ia te a'u.", "and I will do as seemeth me good."]]},
  {num:33,words:[["Fai atu i lenei nuu:", "Say unto this people:"], ["Ia outou filifili i le aso nei,", "Choose ye this day ,"], ["e auauna atu i le Alii le Atua o lē na faia outou.", "to serve the Lord God who made you."]]},
  {num:34,words:[["Faauta ua i ou luga lo'u Agaga,", "Behold my Spirit is upon you,"], ["o le mea lea o au upu uma o le a Ou ta'utonuina;", "wherefore all thy words will I justify;"], ["ma o le a sosola ese mauga i ou luma,", "and the mountains shall flee before you,"], ["ma o le a liliu vaitafe mai i o latou alātafe; ma o le a mau oe ia te a'u,", "and the rivers shall turn from their course;"], ["ma a'u ia te oe;", "and thou shalt abide in me,"], ["o lea,", "and I in you;"], ["savali faatasi ma a'u.", "therefore walk with me."]]},
  {num:35,words:[["Ma sa fetalai mai le Alii ia Enoka,", "And the Lord spake unto Enoch,"], ["ma fai mai ia te ia:", "and said unto him:"], ["Ia ū'u ou mata i le eleele,", "Anoint thine eyes with clay ,"], ["ma fufulu,", "and wash them,"], ["ma o le a e vaai. Ma sa faapea ona faia e ia.", "and thou shalt see. And he did so."]]},
  {num:36,words:[["Ma sa vaai o ia i agaga na foafoaina e le Atua;", "And he beheld the spirits that God had created;"], ["ma sa vaai foi o ia i mea sa lē vaaia e mata faalenatura;", "and he beheld also things which were not visible to the natural eye;"], ["ma mai i le taimi lena i luma na sau ai le tala i le lautele o le laueleele:", "and from thenceforth came the saying abroad in the land:"], ["Ua faatu mai e le Alii se tagatavāai i lona nuu.", "A seer hath the Lord raised up unto his people."]]},
  {num:37,words:[["Ma sa oo ina alu atu Enoka i le laueleele,", "And it came to pass that Enoch went forth in the land,"], ["i totonu o le nuu,", "among the people,"], ["ua tu i luga o maupuepue ma mea maualuluga,", "standing upon the hills and the high places,"], ["ma alaga atu ma le leo tele,", "and cried with a loud voice,"], ["ua molimau atu e faasaga ia latou galuega;", "testifying against their works;"], ["ma sa tausuai tagata uma ona o ia.", "and all men were offended because of him."]]},
  {num:38,words:[["Ma sa latou o mai e faalogologo ia te ia,", "And they came forth to hear him,"], ["i luga o mea maualuluga,", "upon the high places,"], ["ua fai atu i e e tausi-faleie:", "saying unto the tent-keepers :"], ["Ia outou nonofo iinei ma vaavaai faleie,", "Tarry ye here and keep the tents,"], ["a'o matou o i 'o e vaavaai i le tagatavāai,", "while we go yonder to behold the seer,"], ["ona ua vavalo o ia,", "for he prophesieth,"], ["ma ua i ai se mea uiga ese i le laueleele;", "and there is a strange thing in the land;"], ["ua sau se tagata valevale i totonu o i tatou.", "a wild man hath come among us."]]},
  {num:39,words:[["Ma sa oo ina ua latou faalogo atu ia te ia,", "And it came to pass when they heard him,"], ["sa leai se tagata na faaoo atu lima ia te ia;", "no man laid hands on him;"], ["ona sa oo mai le mata'u ia i latou uma o e na faalogo atu ia te ia;", "for fear came on all them that heard him;"], ["aua sa savavali o ia faatasi ma le Atua.", "for he walked with God."]]},
  {num:40,words:[["Ma sa sau se tagata ia te ia,", "And there came a man unto him,"], ["o lona igoa o Maaisa,", "whose name was Mahijah,"], ["ma fai mai ia te ia:", "and said unto him:"], ["Ta'u manino mai ia i matou po o ai oe,", "Tell us plainly who thou art,"], ["ma le mea e te sau ai?", "and from whence thou comest?"]]},
  {num:41,words:[["Ma sa fai atu o ia ia te i latou:", "And he said unto them:"], ["Na ou sau i fafo mai le laueleele o Kainano,", "I came out from the land of Cainan ,"], ["o le laueleele o o'u tamā,", "the land of my fathers,"], ["o se laueleele o le amiotonu e oo mai i le aso nei. Ma sa aoaoina a'u e lo'u tamā i ala uma o le Atua.", "a land of righteousness unto this day. And my father taught me in all the ways of God."]]},
  {num:42,words:[["Ma sa oo ina a'o ou malaga mai le laueleele o Kainano,", "And it came to pass,"], ["i tafatafa o le sami i sasae,", "as I journeyed from the land of Cainan,"], ["sa ou vaaia se faaaliga vaaia;", "by the sea east,"], ["ma faauta,", "I beheld a vision;"], ["sa ou vaai i le lagi,", "and lo,"], ["ma sa fetalai mai le Alii ia te a'u,", "the heavens I saw, and the Lord spake with me,"], ["ma tuu mai ia te a'u se poloaiga;", "and gave me commandment;"], ["o le mea lea,", "wherefore,"], ["ona o le pogai lenei,", "for this cause,"], ["ia tausia le poloaiga,", "to keep the commandment,"], ["ua ou tautala atu ai nei upu.", "I speak forth these words."]]},
  {num:43,words:[["Ma sa faaauau e Enoka lana lauga,", "And Enoch continued his speech,"], ["ua fai atu:", "saying:"], ["O le Alii o lē na fetalai mai ia te a'u,", "The Lord which spake with me,"], ["o lea lava o le Atua o le lagi,", "the same is the God of heaven,"], ["ma o ia o lo'u Atua,", "and he is my God,"], ["ma lo outou Atua,", "and your God,"], ["ma o outou o o'u uso,", "and ye are my brethren,"], ["ma aisea ua outou taupulepule ai ia te outou lava,", "and why counsel ye yourselves,"], ["ma teena le Atua o le lagi?", "and deny the God of heaven?"]]},
  {num:44,words:[["O le lagi na faia e ia;", "The heavens he made;"], ["o le lalolagi o lona tuuvae ;", "the earth is his footstool ;"], ["ma o lona faavae o lana. Faauta,", "and the foundation thereof is his. Behold,"], ["o ia na faataotoina,", "he laid it,"], ["na ia aumai i ona luga se 'au o tagata e toatele.", "an host of men hath he brought in upon the face thereof."]]},
  {num:45,words:[["Ma ua oo mai le oti i luga o o tatou tamā;", "And death hath come upon our fathers;"], ["e ui i lea,", "nevertheless we know them,"], ["ua tatou iloa i latou, ma lē mafai ona faafitia,", "and cannot deny,"], ["ma e oo lava i lē ua muamua i tagata uma ua tatou iloa,", "and even the first of all we know,"], ["o Atamu lava.", "even Adam ."]]},
  {num:46,words:[["Ona ua tatou tusia i totonu o i tatou se tusi faamanatu ,", "For a book of remembrance we have written among us,"], ["e tusa ma le ata na tuu mai e le tamatamaiaao o le Atua;", "according to the pattern given by the finger of God;"], ["ma sa tuuina mai i la tatou lava gagana.", "and it is given in our own language ."]]},
  {num:47,words:[["Ma a'o fetalai atu e Enoka afioga a le Atua,", "And as Enoch spake forth the words of God,"], ["sa tetete tagata,", "the people trembled,"], ["ma lē mafai ona tutu i ona luma.", "and could not stand in his presence."]]},
  {num:48,words:[["Ma sa fai atu o ia ia te i latou:", "And he said unto them:"], ["Ona sa pa'ū Atamu,", "Because that Adam fell ,"], ["ua tatou i ai;", "we are;"], ["ma o lona pa'ū ua oo mai ai le oti ;", "and by his fall came death ;"], ["ma ua oo mai ai ia i tatou le pagatia ma le malaia.", "and we are made partakers of misery and woe."]]},
  {num:49,words:[["Faauta ua sau Satani i totonu o le fanauga a tagata,", "Behold Satan hath come among the children of men,"], ["ma faaosooso i latou e ifo atu ia te ia;", "and tempteth them to worship him;"], ["ma ua avea tagata ma tagata ua faaletino ,", "and men have become carnal ,"], ["ma nautino ,", "sensual ,"], ["ma faaletiapolo,", "and devilish,"], ["ma ua tapunia ese mai luma o le Atua.", "and are shut out from the presence of God."]]},
  {num:50,words:[["Peitai sa faailoa mai e le Atua i o tatou tamā e ao i tagata uma ona salamo.", "But God hath made known unto our fathers that all men must repent."]]},
  {num:51,words:[["Ma sa fetalai mai o ia i lo tatou tamā o Atamu i lona lava siufofoga,", "And he called upon our father Adam by his own voice,"], ["ua fetalai mai:", "saying:"], ["O A'u o le Atua;", "I am God;"], ["o A'u na faia le lalolagi,", "I made the world,"], ["ma tagata ae lei i ai i latou i la le tino.", "and men before they were in the flesh."]]},
  {num:52,words:[["Ma sa fetalai mai foi o ia ia te ia:", "And he also said unto him:"], ["Afai e te liliu mai ia te a'u,", "If thou wilt turn unto me,"], ["ma faalogo mai i lo'u leo,", "and hearken unto my voice,"], ["ma talitonu,", "and believe,"], ["ma salamo i au solitulafono uma,", "and repent of all thy transgressions,"], ["ma papatiso ,", "and be baptized ,"], ["i le vai lava,", "even in water,"], ["i le suafa o lo'u Atalii e Toatasi na Fanaua,", "in the name of mine Only Begotten Son,"], ["o lē ua tumu i le alofa tunoa ma le upumoni,", "who is full of grace and truth,"], ["o Iesu Keriso lea,", "which is Jesus Christ ,"], ["le suafa lava lea e tasi o le a tuuina atu i lalo o le lagi,", "the only name which shall be given under heaven,"], ["o le a oo mai ai le olataga i le fanauga a tagata,", "whereby salvation shall come unto the children of men,"], ["o le a e maua le meaalofa o le Agaga Paia,", "ye shall receive the gift of the Holy Ghost,"], ["ma ole mai i mea uma i lona suafa,", "asking all things in his name,"], ["ma o soo se mea e te ole mai ai,", "and whatsoever ye shall ask,"], ["o le a tuu atu ia te oe.", "it shall be given you."]]},
  {num:53,words:[["Ma sa fai atu lo tatou tamā o Atamu i le Alii,", "And our father Adam spake unto the Lord,"], ["ua fai atu:", "and said:"], ["Aisea e tatau ai i tagata ona salamo ma papatiso i le vai? Ma sa fetalai mai le Alii ia Atamu:", "Why is it that men must repent and be baptized in water? And the Lord said unto Adam:"], ["Faauta ua Ou faamagaloina oe i lau solitulafono i le Faatoaga o Etena.", "Behold I have forgiven thee thy transgression in the Garden of Eden."]]},
  {num:54,words:[["O lea na oo mai ai le tala i totonu o le lautele o le nuu,", "Hence came the saying abroad among the people,"], ["e faapea ua togiola le Alo o le Atua mo le uluai sala,", "that the Son of God hath atoned for original guilt,"], ["lea e lē mafai ai ona tali o agasala a matua i luga o ulu o fanau ,", "wherein the sins of the parents cannot be answered upon the heads of the children ,"], ["ona ua mama i latou mai le faavaega o le lalolagi.", "for they are whole from the foundation of the world."]]},
  {num:55,words:[["Ma sa fetalai mai le Alii ia Atamu,", "And the Lord spake unto Adam,"], ["ua fetalai mai:", "saying:"], ["Talu ai ona ua afuafua au fanau i le agasala,", "Inasmuch as thy children are conceived in sin,"], ["e faapea lava pe a amata ona latou tutupu a'e,", "even so when they begin to grow up,"], ["ona tuputupu o le agasala i o latou loto,", "sin conceiveth in their hearts,"], ["ma latou te tofo i le oona ,", "and they taste the bitter ,"], ["ina ia latou iloa ai ona faataua le lelei.", "that they may know to prize the good."]]},
  {num:56,words:[["Ma ua tuu atu ia te i latou ia iloa le lelei mai le leaga;", "And it is given unto them to know good from evil;"], ["o le mea lea o i latou o ni pule ia i latou lava,", "wherefore they are agents unto themselves,"], ["ma ua Ou tuu ia te oe se isi tulafono ma poloaiga.", "and I have given unto you another law and commandment."]]},
  {num:57,words:[["O le mea lea ia aoao atu i lau fanau,", "Wherefore teach it unto your children,"], ["e ao i tagata uma,", "that all men,"], ["i soo se mea lava,", "everywhere,"], ["ona salamo ,", "must repent ,"], ["po o o le a leai se ala e mafai ai ona latou mautofi i le malo o le Atua,", "or they can in nowise inherit the kingdom of God,"], ["ona e leai se mea lē mama e mafai ona mau iina,", "for no unclean thing can dwell there,"], ["pe mau i ona luma;", "or dwell in his presence ;"], ["ona,", "for,"], ["i le gagana a Atamu,", "in the language of Adam,"], ["o le Tagata Paia o lona suafa lea,", "Man of Holiness is his name,"], ["ma o le suafa o lana Toatasi na Fanaua o le Atalii o le Tagata,", "and the name of his Only Begotten is the Son of Man ,"], ["o Iesu Keriso lava,", "even Jesus Christ ,"], ["o se Faamasino amiotonu,", "a righteous Judge ,"], ["o lē o le a afio mai i le meritiana o taimi.", "who shall come in the meridian of time."]]},
  {num:58,words:[["O lea Ou te tuu atu ia te oe se poloaiga,", "Therefore I give unto you a commandment ,"], ["ia aoao saoloto atu ia mea i lau fanau ,", "to teach these things freely unto your children ,"], ["ua fai atu:", "saying:"]]},
  {num:59,words:[["Ona o le solitulafono ua oo mai ai le pa'ū,", "That by reason of transgression cometh the fall,"], ["o le pa'ū lea ua aumaia le oti,", "which fall bringeth death,"], ["ma talu ai ona sa outou fananau mai i le lalolagi i le vai,", "and inasmuch as ye were born into the world by water,"], ["ma le toto,", "and blood,"], ["ma le agaga ,", "and the spirit ,"], ["lea na Ou faia,", "which I have made,"], ["ma faapea ona avea ai o le efuefu o se tagata ola,", "and so became of dust a living soul,"], ["e faapea lava ona tatau ona toe fanauina o outou i le malo o le lagi,", "even so ye must be born again into the kingdom of heaven,"], ["i le vai ,", "of water ,"], ["ma i le Agaga,", "and of the Spirit,"], ["ma faamamaina i le toto,", "and be cleansed by blood,"], ["o le toto lava lea o la'u Toatasi na Fanaua;", "even the blood of mine Only Begotten;"], ["ina ia mafai ona faapaiaina outou mai agasala uma,", "that ye might be sanctified from all sin,"], ["ma olioli i afioga o le ola faavavau i le lalolagi lenei,", "and enjoy the words of eternal life in this world,"], ["ma le ola faavavau i le lalolagi a sau,", "and eternal life in the world to come,"], ["o le mamalu ola pea lava;", "even immortal glory ;"]]},
  {num:60,words:[["Ona o le vai tou te tausia ai le poloaiga;", "For by the water ye keep the commandment;"], ["o le Agaga e ta'uamiotonu ai outou,", "by the Spirit ye are justified ,"], ["ma o le toto e faapaiaina ai outou;", "and by the blood ye are sanctified ;"]]},
  {num:61,words:[["O lea ua tuu atu ai e mau ia te outou;", "Therefore it is given to abide in you;"], ["o le mau o le lagi;", "the record of heaven;"], ["o le Faamafanafana ;", "the Comforter ;"], ["o mea filemu o le mamalu ola pea;", "the peaceable things of immortal glory;"], ["o le upumoni o mea uma;", "the truth of all things;"], ["o lē e faavaveina mea uma,", "that which quickeneth all things,"], ["lea na te faaolaina mea uma;", "which maketh alive all things;"], ["o lē na te silafia mea uma,", "that which knoweth all things,"], ["ma ua i ai le mana uma tau i le atamai,", "and hath all power according to wisdom,"], ["alofa mutimutivale,", "mercy,"], ["upumoni,", "truth,"], ["fai mea tonu,", "justice,"], ["ma le faamasinotonu.", "and judgment."]]},
  {num:62,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["Ou te fai atu ia te oe:", "I say unto you:"], ["O le fuafuaga lenei o le faaolataga mo tagata uma,", "This is the plan of salvation unto all men,"], ["e ala i le toto o la'u Toatasi na Fanaua,", "through the blood of mine Only Begotten ,"], ["o lē o le a afio mai i le meritiana o taimi.", "who shall come in the meridian of time."]]},
  {num:63,words:[["Ma faauta,", "And behold,"], ["e i ai se faatusa o mea uma,", "all things have their likeness ,"], ["ma ua foafoaina mea uma ma faia e molimau ia te a'u,", "and all things are created and made to bear record of me,"], ["o mea faaletino,", "both things which are temporal,"], ["atoa ma mea faaleagaga;", "and things which are spiritual;"], ["o mea o i le lagi i luga,", "things which are in the heavens above,"], ["ma mea o i luga o le lalolagi,", "and things which are on the earth,"], ["ma mea o i totonu o le lalolagi,", "and things which are in the earth,"], ["ma mea o i lalo o le lalolagi,", "and things which are under the earth,"], ["i luga atoa ma lalo:", "both above and beneath:"], ["ua molimau mea uma ia te a'u.", "all things bear record of me."]]},
  {num:64,words:[["Ma sa oo ina ua uma ona fetalai mai o le Alii ia Atamu,", "And it came to pass,"], ["lo tatou tamā,", "when the Lord had spoken with Adam,"], ["sa tagi atu Atamu i le Alii,", "our father,"], ["ma sa segia ese o ia e le Agaga o le Alii,", "that Adam cried unto the Lord, and he was caught away by the Spirit of the Lord,"], ["ma sa aveina ifo o ia i lalo i totonu o le vai,", "and was carried down into the water,"], ["ma sa faataatia i lalo o le vai ,", "and was laid under the water ,"], ["ma sa aumai o ia i fafo mai le vai.", "and was brought forth out of the water."]]},
  {num:65,words:[["Ma sa faapea ona papatisoina o ia,", "And thus he was baptized,"], ["ma sa afio ifo le Agaga o le Atua i luga o ia,", "and the Spirit of God descended upon him,"], ["ma sa faapea ona fanauina o ia i le Agaga,", "and thus he was born of the Spirit,"], ["ma faaolaolaina i totonu o lona tagata.", "and became quickened in the inner man."]]},
  {num:66,words:[["Ma sa faalogoina e ia se leo mai le lagi,", "And he heard a voice out of heaven,"], ["ua fetalai mai:", "saying:"], ["Ua papatisoina oe i le afi,", "Thou art baptized with fire ,"], ["ma le Agaga Paia. O le mau lenei a le Tamā,", "and with the Holy Ghost. This is the record of the Father,"], ["ma le Alo,", "and the Son,"], ["mai le taimi nei i luma ma le faavavau;", "from henceforth and forever;"]]},
  {num:67,words:[["Ma o oe o se tasi o le faatulagaga a ia o lē ua aunoa ma se amataga o aso po o se gataaga o tausaga,", "And thou art after the order of him who was without beginning of days or end of years,"], ["mai le vavau atoa e oo i le faavavau atoa.", "from all eternity to all eternity."]]},
  {num:68,words:[["Faauta,", "Behold,"], ["ua tasi oe ia te a'u,", "thou art one in me,"], ["o se atalii o le Atua;", "a son of God;"], ["ma ua faapea ona mafai ona avea tagata uma ma o'u atalii . Amene.", "and thus may all become my sons . Amen."]]},
];
renderVerseSet(ms_ch_6_Verses, 'ms-ch6-verses');

var ms_ch_7_Verses = [
  {num:1,words:[["Ma sa oo ina faaauau e Enoka lana lauga,", "And it came to pass that Enoch continued his speech,"], ["ua fai atu:", "saying:"], ["Faauta,", "Behold,"], ["sa aoao mai e lo tatou tamā o Atamu nei mea,", "our father Adam taught these things,"], ["ma e toatele sa talitonu ma ua avea ma atalii o le Atua,", "and many have believed and become the sons of God,"], ["ma e toatele sa lē talitonu,", "and many have believed not,"], ["ma ua fano ia latou agasala,", "and have perished in their sins,"], ["ma o loo tulimata'i i luma ma le mata'u ,", "and are looking forth with fear ,"], ["i le mafatiga,", "in torment,"], ["mo le toasa aasa o le toatama'i o le Atua e sasaa mai i luga o i latou.", "for the fiery indignation of the wrath of God to be poured out upon them."]]},
  {num:2,words:[["Ma mai le taimi lena i luma na amata ai ona vavalo atu o Enoka,", "And from that time forth Enoch began to prophesy,"], ["ua fai atu i tagata,", "saying unto the people,"], ["e faapea:", "that:"], ["A'o ou malaga,", "As I was journeying,"], ["ma tu i luga o le nofoaga o Mausa,", "and stood upon the place Mahujah,"], ["ma tagi atu i le Alii,", "and cried unto the Lord,"], ["sa oo mai ai se siufofoga mai le lagi,", "there came a voice out of heaven,"], ["ua fetalai mai—Ia e liliu,", "saying—Turn ye,"], ["ma ia e alu i luga o le mauga o Simeona.", "and get ye upon the mount Simeon ."]]},
  {num:3,words:[["Ma sa oo ina sa ou liliu ma alu a'e i luga o le mauga;", "And it came to pass that I turned and went up on the mount;"], ["ma a'o ou tu i luga o le mauga,", "and as I stood upon the mount,"], ["sa ou vaai atu ua avanoa le lagi,", "I beheld the heavens open,"], ["ma sa faaofuina a'u i le mamalu ;", "and I was clothed upon with glory ;"]]},
  {num:4,words:[["Ma sa ou vaai i le Alii;", "And I saw the Lord;"], ["ma sa tu mai o ia i luma o o'u mata,", "and he stood before my face,"], ["ma sa talanoa o ia ma a'u,", "and he talked with me,"], ["e pei ona talanoa se tagata ma se isi,", "even as a man talketh one with another,"], ["faafesagai lava;", "face to face ;"], ["ma sa fetalai mai o ia ia te a'u:", "and he said unto me:"], ["Vaai ,", "Look ,"], ["ma o le a Ou faaali atu ia te oe le lalolagi i le va o augatupulaga e tele.", "and I will show unto thee the world for the space of many generations."]]},
  {num:5,words:[["Ma sa oo ina ou vaaia le vanu o Suma,", "And it came to pass that I beheld in the valley of Shum,"], ["ma faauta,", "and lo,"], ["o se nuu tele sa nonofo i faleie,", "a great people which dwelt in tents ,"], ["le nuu lea o Suma.", "which were the people of Shum."]]},
  {num:6,words:[["Ma sa toe fetalai mai le Alii ia te a'u:", "And again the Lord said unto me:"], ["Vaai;", "Look;"], ["ma sa ou vaai agai i matu,", "and I looked towards the north,"], ["ma sa ou vaaia le nuu o Kanana,", "and I beheld the people of Canaan ,"], ["o e sa nonofo i faleie.", "which dwelt in tents."]]},
  {num:7,words:[["Ma sa fetalai mai le Alii ia te a'u:", "And the Lord said unto me:"], ["Vavalo atu;", "Prophesy;"], ["ma sa ou vavalo,", "and I prophesied,"], ["ua fai atu:", "saying:"], ["Faauta o le nuu o Kanana,", "Behold the people of Canaan,"], ["o e ua toatele,", "which are numerous,"], ["o le a o atu e pae tau e faasaga i le nuu o Suma,", "shall go forth in battle array against the people of Shum,"], ["ma o le a latou fasioti ia i latou ina ia faaumatia atoa ai i latou;", "and shall slay them that they shall utterly be destroyed;"], ["ma o le a vaevae e le nuu o Kanana i latou lava i le laueleele,", "and the people of Canaan shall divide themselves in the land,"], ["ma o le a lafulafua le laueleele ma lē fua mai,", "and the land shall be barren and unfruitful,"], ["ma o le a leai se isi nuu e nonofo iina ae nao le nuu o Kanana;", "and none other people shall dwell there but the people of Canaan;"]]},
  {num:8,words:[["Aua faauta,", "For behold,"], ["o le a fetuu e le Alii le laueleele i le vevela tele,", "the Lord shall curse the land with much heat,"], ["ma o lona lafulafua o le a au e faavavau;", "and the barrenness thereof shall go forth forever;"], ["ma sa i ai se faauliuli na oo mai i luga o le fanauga uma a Kanana,", "and there was a blackness came upon all the children of Canaan,"], ["sa inosia ai i latou i totonu o tagata uma.", "that they were despised among all people."]]},
  {num:9,words:[["Ma sa oo ina fetalai mai le Alii ia te a'u:", "And it came to pass that the Lord said unto me:"], ["Vaai;", "Look;"], ["ma sa ou vaai,", "and I looked,"], ["ma sa ou iloa atu le laueleele o Sarona,", "and I beheld the land of Sharon,"], ["ma le laueleele o Enoka,", "and the land of Enoch,"], ["ma le laueleele o Ominara,", "and the land of Omner,"], ["ma le laueleele o Heni,", "and the land of Heni,"], ["ma le laueleele o Semu,", "and the land of Shem,"], ["ma le laueleele o Hana,", "and the land of Haner,"], ["ma le laueleele o Hananaia,", "and the land of Hanannihah,"], ["ma e uma o nonofo ai;", "and all the inhabitants thereof;"]]},
  {num:10,words:[["Ma sa fetalai mai le Alii ia te a'u:", "And the Lord said unto me:"], ["Alu atu i lenei nuu,", "Go to this people,"], ["ma fai atu ia te i latou—Ia salamo ,", "and say unto them— Repent ,"], ["ne'i Ou alu atu ma taia i latou i se fetuu,", "lest I come out and smite them with a curse,"], ["ma latou feoti ai.", "and they die."]]},
  {num:11,words:[["Ma sa ia tuu mai ia te a'u se poloaiga e tatau ona ou papatiso atu i le suafa o le Tamā,", "And he gave unto me a commandment that I should baptize in the name of the Father,"], ["ma le Alo,", "and of the Son,"], ["o lē ua tumu i le alofa tunoa ma le upumoni,", "which is full of grace and truth,"], ["ma le Agaga Paia,", "and of the Holy Ghost,"], ["o lē e molimau e uiga i le Tamā ma le Alo.", "which beareth record of the Father and the Son."]]},
  {num:12,words:[["Ma sa oo ina faaauau ona valaau atu o Enoka i tagata uma,", "And it came to pass that Enoch continued to call upon all the people,"], ["vagana ai le nuu o Kanana,", "save it were the people of Canaan,"], ["ia salamo;", "to repent;"]]},
  {num:13,words:[["Ma sa faapea ona matua tele lava le faatuatua o Enoka sa ia taitaia ai le nuu o le Atua,", "And so great was the faith of Enoch that he led the people of God,"], ["ma sa o mai o latou fili e tau faasaga mai ia te i latou;", "and their enemies came to battle against them;"], ["ma sa ia fetalai atu le afioga a le Alii,", "and he spake the word of the Lord,"], ["ma sa gatete le laueleele,", "and the earth trembled,"], ["ma sosola ese mauga ,", "and the mountains fled,"], ["e tusa ma lana faatonu atu;", "even according to his command;"], ["ma sa liliu ese vaitafe mai i o latou alatafe;", "and the rivers of water were turned out of their course;"], ["ma sa faalogoina le tagi a leona mai le vao;", "and the roar of the lions was heard out of the wilderness;"], ["ma sa matata'u tele atunuu uma,", "and all nations feared greatly,"], ["ona o le mamana tele o le upu a Enoka,", "so powerful was the word of Enoch,"], ["ma ona o le matua tele o le mana o le gagana na tuu mai e le Atua ia te ia.", "and so great was the power of the language which God had given him."]]},
  {num:14,words:[["Sa alu a'e foi i luga se laueleele mai le mea loloto o le sami,", "There also came up a land out of the depth of the sea,"], ["ma sa faapea ona matua tele lava le mata'u o fili o le nuu o le Atua,", "and so great was the fear of the enemies of the people of God,"], ["sa oo ina latou sosola ma tutu mamao ese ma o atu i luga o le laueleele na alu a'e mai le mea loloto o le sami.", "that they fled and stood afar off and went upon the land which came up out of the depth of the sea."]]},
  {num:15,words:[["Ma tagata tino ese o le laueleele,", "And the giants of the land,"], ["sa tutu mamao ese foi;", "also, stood afar off;"], ["ma sa alu atu se fetuu i luga o tagata uma sa faasaga tau i le Atua;", "and there went forth a curse upon all people that fought against God;"]]},
  {num:16,words:[["Ma sa i ai mai le taimi lena i luma taua ma le faamasaatoto i totonu o i latou;", "And from that time forth there were wars and bloodshed among them;"], ["ae sa afio mai le Alii ma mau faatasi ma lona nuu,", "but the Lord came and dwelt with his people,"], ["ma sa latou mau i le amiotonu.", "and they dwelt in righteousness."]]},
  {num:17,words:[["Sa i luga o atunuu uma le mata'u i le Alii,", "The fear of the Lord was upon all nations,"], ["ona sa matua tele lava le mamalu o le Alii,", "so great was the glory of the Lord,"], ["sa i luga o lona nuu. Ma sa faamanuia e le Alii le laueleele,", "which was upon his people. And the Lord blessed the land ,"], ["ma sa faamanuiaina i latou i luga o mauga,", "and they were blessed upon the mountains,"], ["ma i luga o mea maualuluga,", "and upon the high places,"], ["ma sa olaola.", "and did flourish."]]},
  {num:18,words:[["Ma sa ta'ua e le Alii lona nuu o Siona ,", "And the Lord called his people Zion ,"], ["ona sa tasi o latou loto ma tasi le mafaufau,", "because they were of one heart and one mind,"], ["ma sa mau i le amiotonu;", "and dwelt in righteousness;"], ["ma sa leai se mativa i totonu o i latou.", "and there was no poor among them."]]},
  {num:19,words:[["Ma sa faaauau e Enoka lana talaiga i le amiotonu i le nuu o le Atua. Ma sa oo i ona aso,", "And Enoch continued his preaching in righteousness unto the people of God. And it came to pass in his days,"], ["sa fausia e ia se aai sa ta'ua o le Aai Paia,", "that he built a city that was called the City of Holiness,"], ["o Siona lava.", "even Zion ."]]},
  {num:20,words:[["Ma sa oo ina talatala Enoka faatasi ma le Alii;", "And it came to pass that Enoch talked with the Lord;"], ["ma sa fai atu o ia i le Alii:", "and he said unto the Lord:"], ["E moni lava o le a mau Siona i le saogalemu e faavavau. Ae sa fetalai mai le Alii ia Enoka:", "Surely Zion shall dwell in safety forever. But the Lord said unto Enoch:"], ["Ua Ou faamanuiaina Siona,", "Zion have I blessed,"], ["ae o le vaega o totoe o tagata ua Ou fetuuina.", "but the residue of the people have I cursed."]]},
  {num:21,words:[["Ma sa oo ina faaali mai e le Alii ia Enoka tagata uma e nonofo i le lalolagi;", "And it came to pass that the Lord showed unto Enoch all the inhabitants of the earth;"], ["ma sa vaai atu o ia,", "and he beheld,"], ["ma faauta,", "and lo,"], ["o Siona,", "Zion ,"], ["i le aluga o le taimi,", "in process of time,"], ["ua aveina a'e i le lagi. Ma sa fetalai mai le Alii ia Enoka:", "was taken up into heaven. And the Lord said unto Enoch:"], ["Faauta i lo'u nofoaga e faavavau.", "Behold mine abode forever."]]},
  {num:22,words:[["Ma sa vaai foi Enoka i le vaega na totoe o tagata o e o atalii o Atamu;", "And Enoch also beheld the residue of the people which were the sons of Adam;"], ["ma o i latou o se fefiloi o fanau uma a Atamu vagana ai le fanau a Kaino,", "and they were a mixture of all the seed of Adam save it was the seed of Cain,"], ["ona o fanau a Kaino sa uli ,", "for the seed of Cain were black ,"], ["ma sa leai se nofoaga i totonu o i latou.", "and had not place among them."]]},
  {num:23,words:[["Ma ina ua mavae ona aveina a'e o Siona i le lagi ,", "And after that Zion was taken up into heaven ,"], ["sa vaai atu Enoka,", "Enoch beheld ,"], ["ma faauta,", "and lo,"], ["ua i ona luma atunuu uma o le lalolagi;", "all the nations of the earth were before him;"]]},
  {num:24,words:[["Ma sa o mai lea tupulaga ma lea tupulaga;", "And there came generation upon generation;"], ["ma sa maualuga Enoka ma siitia a'e,", "and Enoch was high and lifted up ,"], ["i le loto lava o le Tamā,", "even in the bosom of the Father,"], ["ma le Atalii o le Tagata;", "and of the Son of Man;"], ["ma faauta,", "and behold,"], ["sa i luga o le lalolagi atoa le mana o Satani.", "the power of Satan was upon all the face of the earth."]]},
  {num:25,words:[["Ma sa vaai o ia i agelu ua afifio ifo mai le lagi;", "And he saw angels descending out of heaven;"], ["ma sa ia faalogoina se siufofoga leo tele ua fetalai mai:", "and he heard a loud voice saying:"], ["Oi talofa,", "Wo,"], ["oi talofa i e o nonofo i le lalolagi.", "wo be unto the inhabitants of the earth."]]},
  {num:26,words:[["Ma sa vaai o ia ia Satani;", "And he beheld Satan;"], ["ma sa i ai ia te ia se filifili tele i lona lima,", "and he had a great chain in his hand,"], ["ma sa ufitia ai luga o le lalolagi atoa i le pouliuli ;", "and it veiled the whole face of the earth with darkness ;"], ["ma sa tepa a'e o ia ma 'ata,", "and he looked up and laughed ,"], ["ma sa olioli ana agelu .", "and his angels rejoiced."]]},
  {num:27,words:[["Ma sa vaaia e Enoka agelu ua afifio ifo mai le lagi,", "And Enoch beheld angels descending out of heaven,"], ["ua molimau atu e uiga i le Tamā ma le Alo;", "bearing testimony of the Father and Son;"], ["ma sa pa'ū ifo le Agaga Paia i luga o le toatele,", "and the Holy Ghost fell on many,"], ["ma sa segia a'e i latou i luga i Siona e mana o le lagi.", "and they were caught up by the powers of heaven into Zion."]]},
  {num:28,words:[["Ma sa oo ina silasila ifo le Atua o le lagi i luga o e na totoe o le nuu,", "And it came to pass that the God of heaven looked upon the residue of the people,"], ["ma sa tutulu o ia;", "and he wept;"], ["ma sa molimauina e Enoka lea mea,", "and Enoch bore record of it,"], ["ua fai mai:", "saying:"], ["Pe ua faapefea ea ona tutulu o le lagi,", "How is it that the heavens weep,"], ["ma faamaligi ifo o latou loifofoga e pei o uaga i luga o mauga?", "and shed forth their tears as the rain upon the mountains?"]]},
  {num:29,words:[["Ma sa fai atu Enoka i le Alii:", "And Enoch said unto the Lord:"], ["Pe ua mafai faapefea ona e tutulu ,", "How is it that thou canst weep ,"], ["ona ua vaai ua e paia,", "seeing thou art holy,"], ["ma ua mai le faavavau atoa i le faavavau atoa?", "and from all eternity to all eternity?"]]},
  {num:30,words:[["Ma a na mafai e le tagata ona faitau fasimea o le lalolagi,", "And were it possible that man could number the particles of the earth,"], ["ioe,", "yea,"], ["le miliona o lalolagi e pei o lenei,", "millions of earths like this,"], ["e lē mafai ona avea o se amataga i le aofai o au foafoaga ;", "it would not be a beginning to the number of thy creations ;"], ["ae ua toso atu pea ou ie pupuni;", "and thy curtains are stretched out still;"], ["ma peitai o loo i ai oe iina,", "and yet thou art there,"], ["ma ua i ai iina lou loto;", "and thy bosom is there;"], ["ma ua e fai mea tonu foi;", "and also thou art just;"], ["ua e alofa mutimutivale ma agalelei e faavavau;", "thou art merciful and kind forever;"]]},
  {num:31,words:[["Ma ua e avea Siona i lou lava loto,", "And thou hast taken Zion to thine own bosom,"], ["mai au foafoaga uma,", "from all thy creations,"], ["e mai le faavavau atoa i le faavavau atoa;", "from all eternity to all eternity;"], ["ma ua leai se mea ae ua nao le filemu ,", "and naught but peace,"], ["faamasinotonu ,", "justice ,"], ["ma le upumoni le afioaga o lou nofoaalii;", "and truth is the habitation of thy throne;"], ["ma o le a alu atu le alofamutimutivale i luma o ou fofoga ma e leai se gataaga;", "and mercy shall go before thy face and have no end;"], ["pe ua mafai faapefea ona e tutulu?", "how is it thou canst weep ?"]]},
  {num:32,words:[["Sa fetalai mai le Alii ia Enoka:", "The Lord said unto Enoch:"], ["Faauta ia i latou nei o ou uso;", "Behold these thy brethren;"], ["o i latou o galuega a o'u lava lima ,", "they are the workmanship of mine own hands ,"], ["ma sa Ou tuu atu ia te i latou lo latou malamalama ,", "and I gave unto them their knowledge ,"], ["i le aso na Ou foafoa ai i latou;", "in the day I created them;"], ["ma sa Ou tuu atu i le tagata i le Faatoaga o Etena,", "and in the Garden of Eden,"], ["lona faitalia ;", "gave I unto man his agency ;"]]},
  {num:33,words:[["Ma sa Ou fai atu i ou uso,", "And unto thy brethren have I said,"], ["ma tuu atu foi le poloaiga,", "and also given commandment,"], ["e tatau ona latou alolofa o le tasi i le isi,", "that they should love one another,"], ["ma e tatau ona latou filifili a'u,", "and that they should choose me,"], ["lo latou Tamā;", "their Father;"], ["ae faauta,", "but behold,"], ["ua latou aunoa ma le alofa,", "they are without affection,"], ["ma ua latou inoino i o latou lava toto;", "and they hate their own blood;"]]},
  {num:34,words:[["Ma ua mumu a'e le afi o lo'u ita e faasaga ia te i latou;", "And the fire of mine indignation is kindled against them;"], ["ma o le aasa o lo'u lē fiafia o le a Ou auina atu ai lolo i luga o i latou,", "and in my hot displeasure will I send in the floods upon them,"], ["ona ua mumu a'e lo'u ita tele e faasaga ia te i latou.", "for my fierce anger is kindled against them."]]},
  {num:35,words:[["Faauta,", "Behold,"], ["o A'u o le Atua;", "I am God;"], ["o le Tagata Paia o lo'u igoa lea;", "Man of Holiness is my name; Man of Counsel is my name;"], ["o le Tagata Fautua o lo'u igoa lea;", "and Endless and Eternal is my name ,"], ["ma o Lē Gata ma Faavavau o lo'u igoa foi lea.", "also."]]},
  {num:36,words:[["O le mea lea,", "Wherefore,"], ["e mafai ona faaloloa atu o'u lima ma umia foafoaga uma ua Ou faia;", "I can stretch forth mine hands and hold all the creations which I have made;"], ["ma e mafai foi ona ati ia te i latou o'u mata ;", "and mine eye can pierce them also,"], ["ma i totonu o galuega uma a o'u lima sa le'i i ai lava se amioleaga tele e pei ona i ai i totonu o ou uso.", "and among all the workmanship of mine hands there has not been so great wickedness as among thy brethren."]]},
  {num:37,words:[["Ae faauta,", "But behold,"], ["o a latou agasala o le a i luga o ulu o o latou tamā;", "their sins shall be upon the heads of their fathers;"], ["o le a avea Satani ma o latou tamā,", "Satan shall be their father,"], ["ma o le a avea le pagatia ma o latou malaia;", "and misery shall be their doom;"], ["ma o le a tutulu le lagi atoa i luga o i latou, o le galuega atoa lava a o'u lima;", "and the whole heavens shall weep over them,"], ["o le mea lea,", "even all the workmanship of mine hands;"], ["pe ua lē tatau ea ona tutulu o le lagi,", "wherefore should not the heavens weep,"], ["i le vaai atu o le a mafatia i latou nei?", "seeing these shall suffer?"]]},
  {num:38,words:[["Ae faauta,", "But behold,"], ["o i latou ia o loo silasila atu i ai i luga ou fofoga o le a fano i lolo;", "these which thine eyes are upon shall perish in the floods;"], ["ma faauta,", "and behold,"], ["o le a Ou tapunia i latou;", "I will shut them up;"], ["ua Ou saunia se falepuipui mo i latou.", "a prison have I prepared for them."]]},
  {num:39,words:[["Ma o ia o lē ua Ou filifilia ua aioi mai i luma o o'u mata.", "And that which I have chosen hath pled before my face."], ["O le mea lea,", "Wherefore,"], ["ua mafatia o ia mo a latou agasala;", "he suffereth for their sins;"], ["i le tulaga e oo i ai le latou salamo i le aso e foi mai ai la'u Filifilia ia te a'u, ma seia oo mai lena aso,", "inasmuch as they will repent in the day that my Chosen shall return unto me,"], ["o le a latou i ai i mafatiga ;", "and until that day they shall be in torment ;"]]},
  {num:40,words:[["O le mea lea,", "Wherefore,"], ["ona o lenei mea o le a tutulu ai le lagi,", "for this shall the heavens weep,"], ["ioe,", "yea,"], ["ma galuega uma a o'u lima.", "and all the workmanship of mine hands."]]},
  {num:41,words:[["Ma sa oo ina fetalai mai le Alii ia Enoka,", "And it came to pass that the Lord spake unto Enoch,"], ["ma ta'u mai ia Enoka mea uma ua faia e le fanauga a tagata;", "and told Enoch all the doings of the children of men;"], ["o le mea lea na iloa ai e Enoka,", "wherefore Enoch knew,"], ["ma sa vaai atu i lo latou amioleaga,", "and looked upon their wickedness,"], ["ma lo latou pagatia,", "and their misery,"], ["ma ua tagi ma faaloloa atu ona lima,", "and wept and stretched forth his arms,"], ["ma sa malena lautele lona loto e pei o le faavavau,", "and his heart swelled wide as eternity;"], ["ma mutimutivale ona loto;", "and his bowels yearned;"], ["ma sa luluina le faavavau atoa.", "and all eternity shook."]]},
  {num:42,words:[["Ma sa vaai foi Enoka ia Noa ,", "And Enoch also saw Noah,"], ["ma lona aiga ;", "and his family ;"], ["e faapea o le a laveaiina fanau a atalii uma o Noa i se olataga faaletino;", "that the posterity of all the sons of Noah should be saved with a temporal salvation;"]]},
  {num:43,words:[["O le mea lea na vaai ai Enoka sa fausia e Noa se vaa ;", "Wherefore Enoch saw that Noah built an ark ;"], ["ma sa fiafia le Alii i le vaa,", "and that the Lord smiled upon it,"], ["ma umia i lona lava aao;", "and held it in his own hand;"], ["ae o e na totoe o e na amioleaga na oo mai i ai lolo ma tofatumoanaina i latou.", "but upon the residue of the wicked the floods came and swallowed them up."]]},
  {num:44,words:[["Ma a'o vaai atu Enoka i lenei mea,", "And as Enoch saw this,"], ["sa ia te ia le faanoanoa o le agaga,", "he had bitterness of soul,"], ["ma tagi e uiga i ona uso,", "and wept over his brethren,"], ["ma fai atu i le lagi:", "and said unto the heavens:"], ["O le a ou musu e faamafanafanaina;", "I will refuse to be comforted ;"], ["ae na fetalai mai le Alii ia Enoka:", "but the Lord said unto Enoch:"], ["Ia sii a'e lou loto,", "Lift up your heart,"], ["ma fiafia;", "and be glad;"], ["ma vaai.", "and look."]]},
  {num:45,words:[["Ma sa oo ina vaai atu Enoka;", "And it came to pass that Enoch looked;"], ["ma sa vaaia e ia aiga uma o le lalolagi mai ia Noa;", "and from Noah, he beheld all the families of the earth;"], ["ma sa tagi atu o ia i le Alii,", "and he cried unto the Lord,"], ["ua fai atu:", "saying: When shall the day of the Lord come? When shall the blood of the Righteous be shed,"], ["O afea e oo mai ai le aso o le Alii? O afea e faamaligi ai le toto o le Amiotonu ina ia mafai ona faapaiaina ma maua le ola e faavavau e i latou uma o e e faanoanoa?", "that all they that mourn may be sanctified and have eternal life?"]]},
  {num:46,words:[["Ma sa fetalai mai le Alii:", "And the Lord said:"], ["O le a i le meritiana o taimi,", "It shall be in the meridian of time ,"], ["i aso o le amioleaga ma le tauimasui.", "in the days of wickedness and vengeance."]]},
  {num:47,words:[["Ma faauta,", "And behold,"], ["sa vaai Enoka i le aso o le afio mai o le Atalii o le Tagata,", "Enoch saw the day of the coming of the Son of Man,"], ["i le tino lava;", "even in the flesh;"], ["ma sa olioli lona agaga,", "and his soul rejoiced,"], ["ua fai mai:", "saying:"], ["Ua sii i luga le Amiotonu,", "The Righteous is lifted up,"], ["ma ua fasia le Tamai Mamoe mai le faavaega o le lalolagi;", "and the Lamb is slain from the foundation of the world;"], ["ma ua ou i ai i le loto o le Tamā e ala i le faatuatua,", "and through faith I am in the bosom of the Father,"], ["ma faauta,", "and behold,"], ["ua faatasi Siona ma a'u.", "Zion is with me."]]},
  {num:48,words:[["Ma sa oo ina vaai atu Enoka i luga o le lalolagi ;", "And it came to pass that Enoch looked upon the earth ;"], ["ma sa ia faalogoina se leo mai ona alo,", "and he heard a voice from the bowels thereof,"], ["ua fai mai:", "saying:"], ["Oi talofa,", "Wo,"], ["oi talofa ia te a'u,", "wo is me,"], ["le tinā o tagata;", "the mother of men;"], ["ua ou tiga,", "I am pained ,"], ["ua ou vaivai,", "I am weary,"], ["ona o le amioleaga o la'u fanau. O afea ea ou te mapu ai,", "because of the wickedness of my children. When shall I rest ,"], ["ma faamamaina mai le eleelea ua alu atu i fafo mai ia te a'u? O afea ea e faapaiaina ai a'u e lo'u Foafoa,", "and be cleansed from the filthiness which is gone forth out of me? When will my Creator sanctify me,"], ["ina ia ou mapu,", "that I may rest,"], ["ma mau i o'u luga i se tau le amiotonu?", "and righteousness for a season abide upon my face?"]]},
  {num:49,words:[["Ma ina ua faalogo atu Enoka i le faanoanoa o le lalolagi,", "And when Enoch heard the earth mourn,"], ["sa tutulu o ia,", "he wept,"], ["ma tagi atu i le Alii,", "and cried unto the Lord,"], ["ua fai atu:", "saying:"], ["Le Alii e,", "O Lord,"], ["pe e te lē agaalofa ea i le lalolagi? Pe e te lē faamanuiaina ea le fanau a Noa?", "wilt thou not have compassion upon the earth? Wilt thou not bless the children of Noah?"]]},
  {num:50,words:[["Ma sa oo ina faaauau e Enoka lana tagi atu i le Alii,", "And it came to pass that Enoch continued his cry unto the Lord,"], ["ua fai atu:", "saying:"], ["Ou te ole atu ia te oe,", "I ask thee,"], ["Le Alii e,", "O Lord,"], ["i le suafa o lau Toatasi na Fanaua,", "in the name of thine Only Begotten,"], ["o Iesu Keriso lava,", "even Jesus Christ,"], ["ia e alofa mutimutivale ia Noa ma lana fanau,", "that thou wilt have mercy upon Noah and his seed,"], ["ina ia lē toe ufitia le lalolagi i lolo.", "that the earth might never more be covered by the floods ."]]},
  {num:51,words:[["Ma sa lē mafai e le Alii ona taofia;", "And the Lord could not withhold;"], ["ma sa osifeagaiga o ia ma Enoka,", "and he covenanted with Enoch,"], ["ma tauto mai ia te ia i se tautoga,", "and sware unto him with an oath,"], ["o le a ia taofi lolo ;", "that he would stay the floods ;"], ["o le a ia valaau atu i fanau a Noa;", "that he would call upon the children of Noah;"]]},
  {num:52,words:[["Ma sa ia auina atu se poloai lē masuia,", "And he sent forth an unalterable decree,"], ["o le a i ai pea se toe vaega o ana fanau o le a maua i atunuu uma,", "that a remnant of his seed should always be found among all nations,"], ["a'o tu le lalolagi;", "while the earth should stand;"]]},
  {num:53,words:[["Ma sa fetalai mai le Alii:", "And the Lord said:"], ["Amuia lava o ia o lē o le a ala mai i ana fanau le afio mai o le Mesia;", "Blessed is he through whose seed Messiah shall come;"], ["ona ua fetalai mai o ia—o A'u o le Mesia ,", "for he saith—I am Messiah ,"], ["o le Tupu o Siona,", "the King of Zion,"], ["o le Papa o le Lagi, ua lautele e pei o le faavavau;", "the Rock of Heaven,"], ["ai se e sau i totonu i le faitotoa ma 'a'e mai i luga e ala ia te a'u,", "which is broad as eternity ;"], ["e lē pa'ū lava;", "whoso cometh in at the gate and climbeth up by me shall never fall;"], ["o le mea lea,", "wherefore,"], ["amuia lava i latou o e ua Ou fai atu ai,", "blessed are they of whom I have spoken,"], ["ona o le a latou o mai ma pese o le olioli e faavavau.", "for they shall come forth with songs of everlasting joy ."]]},
  {num:54,words:[["Ma sa oo ina tagi atu Enoka i le Alii,", "And it came to pass that Enoch cried unto the Lord,"], ["ua fai atu:", "saying:"], ["A afio mai le Atalii o le Tagata i le tino,", "When the Son of Man cometh in the flesh,"], ["e mapu ea le lalolagi? Ou te talosaga atu ia te oe,", "shall the earth rest? I pray thee,"], ["faaali mai ia te a'u ia mea.", "show me these things."]]},
  {num:55,words:[["Ma sa fetalai mai le Alii ia Enoka:", "And the Lord said unto Enoch:"], ["Vaai,", "Look,"], ["ma sa vaai o ia ma vaai atu i le Atalii o le Tagata ua sii a'e i luga o le satauro ,", "and he looked and beheld the Son of Man lifted up on the cross ,"], ["e tusa ma le tu a tagata;", "after the manner of men;"]]},
  {num:56,words:[["Ma sa ia faalogoina se siufofoga leotele;", "And he heard a loud voice;"], ["ma sa tapunia le lagi;", "and the heavens were veiled ;"], ["ma sa aue foafoaga uma a le Atua;", "and all the creations of God mourned;"], ["ma sa oi le lalolagi;", "and the earth groaned ;"], ["ma sa mavaevae papa;", "and the rocks were rent;"], ["ma sa tutulai mai le au paia,", "and the saints arose,"], ["ma sa faapaleina i le aao taumatau o le Atalii o le Tagata,", "and were crowned at the right hand of the Son of Man,"], ["i palealii o le mamalu;", "with crowns of glory;"]]},
  {num:57,words:[["Ma o le toatele o agaga sa i ai i le falepuipui sa o mai,", "And as many of the spirits as were in prison came forth,"], ["ma laulaututu i le aao taumatau o le Atua;", "and stood on the right hand of God;"], ["a'o le vaega na totoe sa faapolopolo i filifili o le pouliuli seia oo i le faamasinoga o le aso tele.", "and the remainder were reserved in chains of darkness until the judgment of the great day."]]},
  {num:58,words:[["Ma sa toe tutulu Enoka ma tagi atu i le Alii,", "And again Enoch wept and cried unto the Lord,"], ["ua fai atu:", "saying:"], ["O afea ea e mapu ai le lalolagi?", "When shall the earth rest ?"]]},
  {num:59,words:[["Ma sa vaaia e Enoka le Atalii o le Tagata ua afio a'e i le Tamā;", "And Enoch beheld the Son of Man ascend up unto the Father;"], ["ma sa valaau atu o ia i le Alii,", "and he called unto the Lord,"], ["ua fai atu:", "saying:"], ["Pe e te lē toe afio mai ea i le lalolagi? Talu ai ona o oe o le Atua,", "Wilt thou not come again upon the earth? Forasmuch as thou art God,"], ["ma ua ou iloa oe,", "and I know thee,"], ["ma sa e tauto mai ia te a'u,", "and thou hast sworn unto me,"], ["ma poloaiina a'u ia ou ole atu i le suafa o lau Toatasi na Fanaua;", "and commanded me that I should ask in the name of thine Only Begotten;"], ["na e faia a'u,", "thou hast made me,"], ["ma tuu mai ia te a'u se aiā i lou nofoalii,", "and given unto me a right to thy throne,"], ["ma e lē ona o a'u lava,", "and not of myself,"], ["ae e ala i lou lava alofa tunoa;", "but through thine own grace;"], ["o le mea lea,", "wherefore,"], ["ou te fesili atu ai ia te oe pe e te lē toe afio mai i le lalolagi.", "I ask thee if thou wilt not come again on the earth."]]},
  {num:60,words:[["Ma sa fetalai mai le Alii ia Enoka:", "And the Lord said unto Enoch:"], ["E pei ona Ou ola,", "As I live,"], ["o le a faapea lava ona Ou alu atu i aso e gata ai,", "even so will I come in the last days ,"], ["i aso o le amioleaga ma le tauimasui,", "in the days of wickedness and vengeance,"], ["e faataunuu le tautoga na Ou faia ia te oe e uiga i le fanau a Noa;", "to fulfil the oath which I have made unto you concerning the children of Noah;"]]},
  {num:61,words:[["Ma o le a oo mai le aso o le a mapu ai le lalolagi,", "And the day shall come that the earth shall rest ,"], ["peitai ae lei oo mai lena aso o le a faapouliuligia le lagi,", "but before that day the heavens shall be darkened ,"], ["ma o le a ufitia le lalolagi i se veli o le pogisa;", "and a veil of darkness shall cover the earth;"], ["ma o le a luluina le lagi,", "and the heavens shall shake,"], ["ma le lalolagi foi;", "and also the earth;"], ["ma o le a i ai puapuaga e tele i totonu o le fanauga a tagata,", "and great tribulations shall be among the children of men,"], ["ae o lo'u nuu o le a Ou faasaoina ;", "but my people will I preserve ;"]]},
  {num:62,words:[["Ma o le a Ou auina atu i lalo mai le lagi le amiotonu ;", "And righteousness will I send down out of heaven;"], ["ma o le a Ou auina atu le upumoni i fafo mai le eleele ,", "and truth will I send forth out of the earth,"], ["e molimau atu i la'u Toatasi na Fanaua;", "to bear testimony of mine Only Begotten;"], ["lona toetu mai le maliu;", "his resurrection from the dead;"], ["ioe,", "yea,"], ["ma le toetutu mai foi o tagata uma;", "and also the resurrection of all men;"], ["ma o le a Ou faia ia tafi le lalolagi i le amiotonu ma le upumoni e pei o se lolo,", "and righteousness and truth will I cause to sweep the earth as with a flood,"], ["e faapotopoto mai i fafo la'u au filifilia mai itu e fa o le lalolagi,", "to gather out mine elect from the four quarters of the earth,"], ["i se nofoaga o le a Ou saunia,", "unto a place which I shall prepare,"], ["o se Aai Paia,", "an Holy City,"], ["ina ia mafai e lo'u nuu ona fusia i o latou sulugatiti,", "that my people may gird up their loins,"], ["ma tulimatai i le taimi o lo'u alu atu;", "and be looking forth for the time of my coming;"], ["ona o iina o le a i ai lo'u fale fetafai,", "for there shall be my tabernacle,"], ["ma o le a ta'ua ai o Siona,", "and it shall be called Zion ,"], ["o se Ierusalema Fou.", "a New Jerusalem ."]]},
  {num:63,words:[["Ma sa fetalai mai le Alii ia Enoka:", "And the Lord said unto Enoch:"], ["Ona feiloa'i ai lea o oe ma lou aai atoa ma i latou iina,", "Then shalt thou and all thy city meet them there,"], ["ma o le a tatou talia i latou i o tatou loto,", "and we will receive them into our bosom,"], ["ma o le a latou vaai mai ia te i tatou;", "and they shall see us;"], ["ma o le a tatou fusi i o latou ua,", "and we will fall upon their necks,"], ["ma o le a latou fusi foi i o tatou ua,", "and they shall fall upon our necks,"], ["ma o le a tatou sogi foi le tasi i le isi;", "and we will kiss each other;"]]},
  {num:64,words:[["Ma o le a iina lo'u nofoaga,", "And there shall be mine abode,"], ["ma o le a avea ma Siona,", "and it shall be Zion,"], ["lea o le a sau mai foafoaga uma ua Ou faia;", "which shall come forth out of all the creations which I have made;"], ["ma o le a mapu le lalolagi i va o le afe tausaga.", "and for the space of a thousand years the earth shall rest ."]]},
  {num:65,words:[["Ma sa oo ina vaai Enoka i le aso o le afio mai o le Atalii o le Tagata,", "And it came to pass that Enoch saw the day of the coming of the Son of Man,"], ["i aso e gata ai,", "in the last days,"], ["e afio i luga o le lalolagi i le amiotonu i le va o le afe tausaga;", "to dwell on the earth in righteousness for the space of a thousand years;"]]},
  {num:66,words:[["Peitai ae lei oo mai lena aso,", "But before that day he saw great tribulations among the wicked;"], ["sa vaai o ia i puapuaga tetele i totonu o e ua amioleaga;", "and he also saw the sea,"], ["ma sa vaai foi o ia i le sami, ua loulouā,", "that it was troubled,"], ["ma loto o tagata ua faavaivai ,", "and men’s hearts failing them,"], ["ua tulimatai i luma ma le matata'u i faamasinoga a le Atua Malosi Aoao,", "looking forth with fear for the judgments of the Almighty God,"], ["o le a oo mai i luga o e ua amioleaga.", "which should come upon the wicked."]]},
  {num:67,words:[["Ma sa faaali mai e le Alii ia Enoka mea uma,", "And the Lord showed Enoch all things,"], ["e oo lava i le gataaga o le lalolagi;", "even unto the end of the world;"], ["ma sa vaai o ia i le aso o e ua amiotonu,", "and he saw the day of the righteous,"], ["le itula o lo latou togiolaina,", "the hour of their redemption,"], ["ma maua se atoatoaga o le olioli ;", "and received a fulness of joy ;"]]},
  {num:68,words:[["Ma o aso uma o Siona ,", "And all the days of Zion ,"], ["i aso o Enoka,", "in the days of Enoch,"], ["e tolu selau onosefulu ma le lima tausaga.", "were three hundred and sixty-five years."]]},
  {num:69,words:[["Ma sa savavali Enoka ma lona nuu atoa faatasi ma le Atua,", "And Enoch and all his people walked with God,"], ["ma sa afio o ia i le totonugalemu o Siona;", "and he dwelt in the midst of Zion;"], ["ma sa oo ina lē toe i ai Siona,", "and it came to pass that Zion was not,"], ["ona ua aveina a'e i luga e le Atua i lona lava loto;", "for God received it up into his own bosom;"], ["ma mai i le taimi lena na alu atu ai upu,", "and from thence went forth the saying,"], ["Ua sola Siona .", "Zion is Fled ."]]},
];
renderVerseSet(ms_ch_7_Verses, 'ms-ch7-verses');

var ms_ch_8_Verses = [
  {num:1,words:[["Ma o aso uma o Enoka e fa selau tolusefulu tausaga.", "And all the days of Enoch were four hundred and thirty years."]]},
  {num:2,words:[["Ma sa oo ina lei avea Metusela ,", "And it came to pass that Methuselah,"], ["le atalii o Enoka,", "the son of Enoch,"], ["ina ia mafai ona faataunuu o feagaiga a le Alii,", "was not taken, that the covenants of the Lord might be fulfilled,"], ["na faia e ia ia Enoka;", "which he made to Enoch;"], ["ona sa osifeagaiga moni lava o ia ma Enoka o le a avea Noa ma fua o ona sulugatiti.", "for he truly covenanted with Enoch that Noah should be of the fruit of his loins."]]},
  {num:3,words:[["Ma sa oo ina vavalo atu Metusela o le a tutupu mai i ona sulugatiti malo uma o le lalolagi (e ala ia Noa),", "And it came to pass that Methuselah prophesied that from his loins should spring all the kingdoms of the earth (through Noah),"], ["ma sa ia ave le mamalu ia te ia lava.", "and he took glory unto himself."]]},
  {num:4,words:[["Ma sa oo mai se oge tele i le laueleele,", "And there came forth a great famine into the land,"], ["ma sa fetuu e le Alii le laueleele i se fetuu tiga,", "and the Lord cursed the earth with a sore curse,"], ["ma e toatele e sa nonofo ai na feoti ai.", "and many of the inhabitants thereof died."]]},
  {num:5,words:[["Ma sa oo ina ola Metusela i tausaga e selau valusefulu ma le fitu,", "And it came to pass that Methuselah lived one hundred and eighty-seven years,"], ["ma fanaua Lameko;", "and begat Lamech;"]]},
  {num:6,words:[["Ma sa ola Metusela,", "And Methuselah lived,"], ["ina ua uma ona fanauina e ia Lameko,", "after he begat Lamech,"], ["i tausaga e fitu selau valusefulu ma le lua,", "seven hundred and eighty-two years,"], ["ma fanauina atalii ma afafine;", "and begat sons and daughters;"]]},
  {num:7,words:[["Ma o aso uma o Metusela e iva selau onosefulu ma le iva tausaga,", "And all the days of Methuselah were nine hundred and sixty-nine years,"], ["ma sa maliu o ia.", "and he died."]]},
  {num:8,words:[["Ma sa ola Lameko i tausaga e selau valusefulu ma le lua,", "And Lamech lived one hundred and eighty-two years,"], ["ma fanauaina se atalii,", "and begat a son,"]]},
  {num:9,words:[["Ma sa faaigoa e ia o Noa ,", "And he called his name Noah,"], ["ua fai mai:", "saying:"], ["O le atalii lenei o le a faamafanafanaina i tatou e faatatau i la tatou galuega ma le tautiga o o tatou lima,", "This son shall comfort us concerning our work and toil of our hands,"], ["ona o le eleele ua fetuuina e le Alii.", "because of the ground which the Lord hath cursed ."]]},
  {num:10,words:[["Ma sa ola Lameko,", "And Lamech lived,"], ["ina ua uma ona fanauina e ia Noa,", "after he begat Noah,"], ["i tausaga e lima selau ma le ivasefulu lima,", "five hundred and ninety-five years,"], ["ma fanauina atalii ma afafine;", "and begat sons and daughters;"]]},
  {num:11,words:[["Ma o aso uma o Lameko e fitu selau fitusefulu ma le fitu,", "And all the days of Lamech were seven hundred and seventy-seven years,"], ["ma sa maliu o ia.", "and he died."]]},
  {num:12,words:[["Ma sa fa selau limasefulu tausaga o le matua o Noa,", "And Noah was four hundred and fifty years old,"], ["ma sa fanauina Iafeta;", "and begat Japheth;"], ["ma o le fasefulu ma le lua tausaga ina ua mavae lea, na fanauina ai e ia Semu mai ia te ia o lē o le tinā o Iafeta,", "and forty-two years afterward he begat Shem of her who was the mother of Japheth,"], ["ma ina ua lima selau tausaga o lona matua sa fanauina e ia Hamo .", "and when he was five hundred years old he begat Ham ."]]},
  {num:13,words:[["Ma sa faalogo Noa ma ona atalii i le Alii,", "And Noah and his sons hearkened unto the Lord,"], ["ma uai atu,", "and gave heed,"], ["ma sa ta'ua i latou o atalii o le Atua.", "and they were called the sons of God."]]},
  {num:14,words:[["Ma ina ua amata ona uluola nei alii i luga o le lalolagi,", "And when these men began to multiply on the face of the earth,"], ["ma fananau mai afafine ia te i latou,", "and daughters were born unto them,"], ["sa vaai mai atalii o tagata i ia afafine ua lalelei,", "the sons of men saw that those daughters were fair,"], ["ma sa latou ave i latou e fai ma ava,", "and they took them wives ,"], ["e pei lava ona latou filifili i ai.", "even as they chose."]]},
  {num:15,words:[["Ma sa fetalai mai le Alii ia Noa:", "And the Lord said unto Noah:"], ["Ua faatau atu e afafine o ou atalii i latou lava;", "The daughters of thy sons have sold themselves;"], ["aua faauta, ua mumu a'e lo'u ita e faasaga i atalii o tagata,", "for behold mine anger is kindled against the sons of men,"], ["ona ua latou lē fia faalogo mai i lo'u leo.", "for they will not hearken to my voice."]]},
  {num:16,words:[["Ma sa oo ina vavalo atu Noa,", "And it came to pass that Noah prophesied ,"], ["ma aoao atu mea a le Atua,", "and taught the things of God,"], ["e pei lava ona sa i ai i le amataga.", "even as it was in the beginning."]]},
  {num:17,words:[["Ma sa fetalai mai le Alii ia Noa:", "And the Lord said unto Noah:"], ["O le a lē taumafai pea lo'u Agaga i le tagata,", "My Spirit shall not always strive with man,"], ["ona o le a iloa e ia o le a oti tagata uma;", "for he shall know that all flesh shall die;"], ["e ui i lea o ona aso o le a selau luasefulu tausaga;", "yet his days shall be an hundred and twenty years;"], ["ma afai e lē salamo tagata,", "and if men do not repent,"], ["o le a Ou auina atu lolo i luga o i latou.", "I will send in the floods upon them."]]},
  {num:18,words:[["Ma i aso na sa i ai tagata tinoese i luga o le lalolagi,", "And in those days there were giants on the earth,"], ["ma sa latou saili Noa e faaumatia lona ola;", "and they sought Noah to take away his life ;"], ["peitai sa faatasi le Alii ma Noa,", "but the Lord was with Noah,"], ["ma sa i ona luga le mana o le Alii.", "and the power of the Lord was upon him."]]},
  {num:19,words:[["Ma sa faauu e le Alii Noa i lana lava faatulagaga ,", "And the Lord ordained Noah after his own order ,"], ["ma poloaiina o ia e tatau ona alu atu o ia ma folafola atu lana Talalelei i le fanauga a tagata,", "and commanded him that he should go forth and declare his Gospel unto the children of men,"], ["e pei lava ona tuuina atu ia Enoka.", "even as it was given unto Enoch."]]},
  {num:20,words:[["Ma sa oo ina valaau atu Noa i le fanauga a tagata e tatau ona latou salamo ;", "And it came to pass that Noah called upon the children of men that they should repent ;"], ["peitai sa latou lē faalogo mai i ana upu;", "but they hearkened not unto his words;"]]},
  {num:21,words:[["O lenei foi,", "And also,"], ["ina ua uma ona latou faalogo mai ia te ia,", "after that they had heard him,"], ["sa latou o mai i luma o ia,", "they came up before him,"], ["ua fai mai:", "saying:"], ["Faauta,", "Behold,"], ["o i matou o atalii o le Atua;", "we are the sons of God;"], ["matou te lei avea ea ia te i matou afafine o tagata? Ma matou te lē o aai ea ma feinu,", "have we not taken unto ourselves the daughters of men? And are we not eating and drinking,"], ["ma faiava ma tuuina atu i le faaipoipoga? Ma ua fanauina e a matou ava mo matou ni fanau,", "and marrying and giving in marriage? And our wives bear unto us children,"], ["ma o latou lava o ni tagata malolosi,", "and the same are mighty men,"], ["ua faapei o alii anamua,", "which are like unto men of old,"], ["o ni alii ta'uta'ua tele. Ma sa latou lē faalogo mai i upu a Noa.", "men of great renown. And they hearkened not unto the words of Noah."]]},
  {num:22,words:[["Ma sa silasila mai le Atua ua faateteleina le amioleaga o tagata i le lalolagi;", "And God saw that the wickedness of men had become great in the earth;"], ["ma ua faafefeteina i luga tagata taitoatasi i manatunatuga o mafaufauga o lona lava loto,", "and every man was lifted up in the imagination of the thoughts of his heart,"], ["ua nao le leaga e lē aunoa.", "being only evil continually."]]},
  {num:23,words:[["Ma sa oo ina faaauau pea e Noa lana talaiga i le nuu,", "And it came to pass that Noah continued his preaching unto the people,"], ["ua fai atu:", "saying: Hearken,"], ["Faalogo mai ia ma uai mai i a'u upu;", "and give heed unto my words;"]]},
  {num:24,words:[["Ia talitonu ma salamo ia outou agasala ma papatiso i le suafa o Iesu Keriso,", "Believe and repent of your sins and be baptized in the name of Jesus Christ,"], ["le Alo o le Atua,", "the Son of God,"], ["e pei lava o o tatou tamā,", "even as our fathers,"], ["ma o le a outou maua le Agaga Paia,", "and ye shall receive the Holy Ghost,"], ["ina ia mafai ona faaali mai o mea uma ia te outou; ma afai tou te lē faia lenei mea,", "that ye may have all things made manifest ;"], ["o le a oo mai lolo i luga o outou;", "and if ye do not this,"], ["e ui i lea,", "the floods will come in upon you;"], ["sa latou lē faalogo.", "nevertheless they hearkened not."]]},
  {num:25,words:[["Ma sa salamo Noa,", "And it repented Noah,"], ["ma sa tiga lona loto ona ua faia e le Alii le tagata i luga o le lalolagi,", "and his heart was pained that the Lord had made man on the earth,"], ["ma sa faanoanoa ai o ia i lona loto.", "and it grieved him at the heart."]]},
  {num:26,words:[["Ma sa fetalai mai le Alii:", "And the Lord said:"], ["O le a Ou faaumatia le tagata o lē na Ou faia,", "I will destroy man whom I have created,"], ["mai luga o le lalolagi,", "from the face of the earth,"], ["o tagata atoa ma manu vaefa,", "both man and beast,"], ["ma mea fetolofi ma manu felelei o le ea;", "and the creeping things, and the fowls of the air;"], ["ona ua salamo Noa ua Ou foafoaina i latou,", "for it repenteth Noah that I have created them,"], ["ma ua Ou faia i latou;", "and that I have made them;"], ["ma ua valaau mai o ia ia te a'u;", "and he hath called upon me;"], ["aua ua latou saili lona ola.", "for they have sought his life ."]]},
  {num:27,words:[["Ma sa faapea ona maua e Noa le alofa tunoa i fofoga-silasila o le Alii;", "And thus Noah found grace in the eyes of the Lord;"], ["aua o Noa o se tagata sa amiotonu,", "for Noah was a just man,"], ["ma atoatoa i lana tupulaga;", "and perfect in his generation;"], ["ma sa savavali o ia faatasi ma le Atua,", "and he walked with God,"], ["faapea foi ona atalii e toatolu,", "as did also his three sons,"], ["o Semu,", "Shem,"], ["Hamo,", "Ham,"], ["ma Iafeta.", "and Japheth."]]},
  {num:28,words:[["Sa eleelea le lalolagi i luma o le Atua,", "The earth was corrupt before God,"], ["ma sa tumu i le faasaua.", "and it was filled with violence."]]},
  {num:29,words:[["Ma sa silasila mai le Atua i luga o le lalolagi,", "And God looked upon the earth,"], ["ma,", "and,"], ["faauta,", "behold,"], ["ua eleelea,", "it was corrupt,"], ["ona ua faaeleelea e tagata uma o latou ala i luga o le lalolagi.", "for all flesh had corrupted its way upon the earth."]]},
  {num:30,words:[["Ma sa fetalai mai le Atua ia Noa:", "And God said unto Noah:"], ["Ua oo mai le iuga o tagata uma i o'u luma,", "The end of all flesh is come before me,"], ["ona ua tumu le lalolagi i le faasaua,", "for the earth is filled with violence,"], ["ma faauta o le a Ou faaumatia ese tagata uma mai le lalolagi.", "and behold I will destroy all flesh from off the earth."]]},
];
renderVerseSet(ms_ch_8_Verses, 'ms-ch8-verses');

})();